fn env_value(key: &str, fallback: &str) -> String {
    env::var(key)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| fallback.to_string())
}

fn env_bool(key: &str, fallback: bool) -> bool {
    env::var(key)
        .ok()
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            )
        })
        .unwrap_or(fallback)
}

fn now_ms() -> u128 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis()
}

fn request_id(input: Option<&String>, prefix: &str) -> String {
    input
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .unwrap_or(prefix)
        .chars()
        .take(MAX_REQUEST_ID_LEN)
        .collect()
}

fn validate_text(value: &str, label: &str, max_len: usize) -> Result<String, String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return Err(format!("{label} must not be empty"));
    }
    if trimmed.len() > max_len {
        return Err(format!("{label} must be at most {max_len} bytes"));
    }
    if trimmed
        .chars()
        .any(|character| character.is_control() && character != '\n')
    {
        return Err(format!("{label} must not contain control characters"));
    }
    Ok(trimmed.to_string())
}

fn validate_label(value: &str, label: &str) -> Result<String, String> {
    let trimmed = validate_text(value, label, MAX_LABEL_LEN)?;
    if !trimmed
        .chars()
        .all(|character| character.is_ascii_alphanumeric() || matches!(character, '-' | '_' | '.'))
    {
        return Err(format!(
            "{label} may contain only ASCII letters, numbers, '-', '_', or '.'"
        ));
    }
    Ok(trimmed)
}

fn finite_positive(value: f64, label: &str) -> Result<f64, String> {
    if !value.is_finite() || value <= 0.0 {
        return Err(format!("{label} must be finite and positive"));
    }
    Ok(value)
}

fn finite_non_negative(value: f64, label: &str) -> Result<f64, String> {
    if !value.is_finite() || value < 0.0 {
        return Err(format!("{label} must be finite and non-negative"));
    }
    Ok(value)
}

fn finite_ratio(value: f64, label: &str) -> Result<f64, String> {
    if !value.is_finite() || !(0.0..=1.0).contains(&value) {
        return Err(format!("{label} must be finite and in [0, 1]"));
    }
    Ok(value)
}

fn bounded(value: f64, min: f64, max: f64) -> f64 {
    value.max(min).min(max)
}

fn validate_optional_label(value: Option<String>, label: &str) -> Result<Option<String>, String> {
    value.map(|value| validate_label(&value, label)).transpose()
}

fn validate_optional_text(
    value: Option<String>,
    label: &str,
    max_len: usize,
) -> Result<Option<String>, String> {
    value
        .map(|value| validate_text(&value, label, max_len))
        .transpose()
}

fn validate_signal_list(
    values: Option<Vec<String>>,
    label: &str,
    max_len: usize,
) -> Result<Vec<String>, String> {
    let values = values.unwrap_or_default();
    if values.len() > MAX_LEARNING_SIGNALS {
        return Err(format!(
            "{label} must contain at most {MAX_LEARNING_SIGNALS} entries"
        ));
    }
    values
        .into_iter()
        .enumerate()
        .map(|(index, value)| validate_text(&value, &format!("{label}[{index}]"), max_len))
        .collect()
}

fn validate_machine_profile_evidence_list(
    values: Option<Vec<String>>,
    label: &str,
) -> Result<Option<Vec<String>>, String> {
    let Some(values) = values else {
        return Ok(None);
    };
    if values.len() > MAX_MACHINE_PROFILE_EVIDENCE {
        return Err(format!(
            "{label} must contain at most {MAX_MACHINE_PROFILE_EVIDENCE} entries"
        ));
    }
    let values = values
        .into_iter()
        .enumerate()
        .map(|(index, value)| validate_text(&value, &format!("{label}[{index}]"), MAX_TEXT_LEN))
        .collect::<Result<Vec<_>, _>>()?;
    if values.is_empty() {
        Ok(None)
    } else {
        Ok(Some(values))
    }
}

fn validate_machine_profile_evidence(
    evidence: Option<MachineProfileEvidence>,
    label: &str,
) -> Result<Option<MachineProfileEvidence>, String> {
    let Some(evidence) = evidence else {
        return Ok(None);
    };
    let evidence = MachineProfileEvidence {
        calibration: validate_machine_profile_evidence_list(
            evidence.calibration,
            &format!("{label}.calibration"),
        )?,
        tools: validate_machine_profile_evidence_list(evidence.tools, &format!("{label}.tools"))?,
        fixtures: validate_machine_profile_evidence_list(
            evidence.fixtures,
            &format!("{label}.fixtures"),
        )?,
        materials: validate_machine_profile_evidence_list(
            evidence.materials,
            &format!("{label}.materials"),
        )?,
        process: validate_machine_profile_evidence_list(
            evidence.process,
            &format!("{label}.process"),
        )?,
        maintenance: validate_machine_profile_evidence_list(
            evidence.maintenance,
            &format!("{label}.maintenance"),
        )?,
        release: validate_machine_profile_evidence_list(
            evidence.release,
            &format!("{label}.release"),
        )?,
        blockers: validate_machine_profile_evidence_list(
            evidence.blockers,
            &format!("{label}.blockers"),
        )?,
    };
    if evidence.calibration.is_none()
        && evidence.tools.is_none()
        && evidence.fixtures.is_none()
        && evidence.materials.is_none()
        && evidence.process.is_none()
        && evidence.maintenance.is_none()
        && evidence.release.is_none()
        && evidence.blockers.is_none()
    {
        Ok(None)
    } else {
        Ok(Some(evidence))
    }
}

fn stock_envelope_excesses(
    stock_dimensions: &[f64],
    work_envelope: &[f64],
) -> Vec<(usize, f64, f64)> {
    stock_dimensions
        .iter()
        .zip(work_envelope.iter())
        .enumerate()
        .filter_map(|(index, (stock, limit))| {
            if stock > limit {
                Some((index, *stock, *limit))
            } else {
                None
            }
        })
        .collect()
}

fn normalize_token(value: &str) -> String {
    value
        .trim()
        .to_ascii_lowercase()
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() {
                character
            } else {
                '-'
            }
        })
        .collect::<String>()
        .split('-')
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>()
        .join("-")
}

fn safe_job_id(kind: &str, request_id: &str, generated_at_ms: u128) -> String {
    let request = normalize_token(request_id);
    let request = if request.is_empty() {
        "request".to_string()
    } else {
        request
    };
    format!("{}-{}-{}", normalize_token(kind), request, generated_at_ms)
        .chars()
        .take(180)
        .collect()
}

fn summary_text(value: &str) -> String {
    let text = value.trim();
    if text.chars().count() <= 240 {
        text.to_string()
    } else {
        format!("{}...", text.chars().take(237).collect::<String>())
    }
}

impl FabricationArtifact {
    fn summary(&self) -> FabricationArtifactSummary {
        FabricationArtifactSummary {
            artifact_id: self.artifact_id.clone(),
            kind: self.kind.clone(),
            media_type: self.media_type.clone(),
            part_id: self.part_id.clone(),
            program_id: self.program_id.clone(),
            machine_kind: self.machine_kind.clone(),
            draft: self.draft,
            machine_ready: self.machine_ready,
            line_count: self.line_count,
            created_at_ms: self.created_at_ms,
        }
    }
}

impl FabricationJobStore {
    fn new(max_jobs: usize) -> Self {
        Self {
            order: VecDeque::new(),
            jobs: BTreeMap::new(),
            max_jobs: max_jobs.max(1),
        }
    }

    fn insert(&mut self, job: StoredFabricationJob) {
        let job_id = job.record.job_id.clone();
        self.order.retain(|existing| existing != &job_id);
        self.order.push_back(job_id.clone());
        self.jobs.insert(job_id, job);
        while self.order.len() > self.max_jobs {
            if let Some(oldest) = self.order.pop_front() {
                self.jobs.remove(&oldest);
            }
        }
    }

    fn list(&self) -> Vec<FabricationJobRecord> {
        self.order
            .iter()
            .rev()
            .filter_map(|job_id| self.jobs.get(job_id))
            .map(|job| job.record.clone())
            .collect()
    }

    fn detail(&self, job_id: &str) -> Option<FabricationJobDetail> {
        self.jobs.get(job_id).map(|job| FabricationJobDetail {
            record: job.record.clone(),
            plan: job.plan.clone(),
            analysis: job.analysis.clone(),
            learning: job.learning.clone(),
            artifacts: job
                .artifacts
                .values()
                .map(FabricationArtifact::summary)
                .collect(),
        })
    }

    fn artifact(&self, job_id: &str, artifact_id: &str) -> Option<FabricationArtifact> {
        self.jobs
            .get(job_id)
            .and_then(|job| job.artifacts.get(artifact_id))
            .cloned()
    }

    fn counts(&self) -> (usize, usize) {
        let artifact_count = self.jobs.values().map(|job| job.artifacts.len()).sum();
        (self.jobs.len(), artifact_count)
    }
}

impl LearningAggregate {
    fn add(&mut self, outcome: &LearningOutcomeRecord) {
        self.samples += 1;
        if outcome.success {
            self.successes += 1;
        }
        self.reward_sum += outcome.reward;
    }

    fn preference(&self, key: String) -> LearningPreference {
        let failures = self.samples.saturating_sub(self.successes);
        let average_reward = if self.samples == 0 {
            0.0
        } else {
            self.reward_sum / self.samples as f64
        };
        let success_rate = if self.samples == 0 {
            0.0
        } else {
            self.successes as f64 / self.samples as f64
        };
        let recommendation = if self.samples < 2 {
            "explore".to_string()
        } else if success_rate >= 0.66 && average_reward >= 0.0 {
            "prefer".to_string()
        } else if success_rate < 0.4 || average_reward < 0.0 {
            "review-or-avoid".to_string()
        } else {
            "keep-exploring".to_string()
        };
        LearningPreference {
            key,
            samples: self.samples,
            successes: self.successes,
            failures,
            average_reward,
            recommendation,
        }
    }
}

fn remediation_signal(value: &str) -> Option<String> {
    let token = normalize_token(value);
    if token.contains("machine-failure")
        || token.contains("scrap")
        || token.contains("human-intervention")
        || token.contains("dimensional-error")
        || token.contains("surface-quality")
        || token.contains("outcome-root-cause")
        || token.contains("outcome-remediation-action")
        || token.contains("outcome-state")
        || token.contains("chatter")
        || token.contains("collision")
        || token.contains("alarm")
    {
        Some(token)
    } else {
        None
    }
}

fn remediation_action_signal(value: &str) -> Option<String> {
    let token = normalize_token(value);
    if token.contains("outcome-recommended-action") {
        Some(token)
    } else if token.contains("split") || token.contains("combine") || token.contains("review") {
        Some(format!(
            "review-learned-remediation-{}",
            normalize_token(value)
        ))
    } else {
        None
    }
}

fn observation_has_boundary_learning_signal(observation: &str) -> bool {
    let trimmed = observation.trim().to_ascii_lowercase();
    if trimmed.starts_with("boundary-kind:")
        || trimmed.starts_with("boundary-severity:")
        || trimmed.starts_with("boundary-program:")
        || trimmed.starts_with("boundary-line:")
        || trimmed.starts_with("resolution-action:")
        || trimmed.starts_with("suggested-resolution:")
    {
        return true;
    }
    let token = normalize_token(&trimmed);
    token.contains("machine-failure")
        || token.contains("human-intervention-required")
        || token.contains("split-combine")
        || token.contains("combine-separate")
        || token.contains("separate-piece")
        || token.contains("split-piece")
}

fn boundary_learning_example(outcome: &LearningOutcomeRecord) -> Option<String> {
    let observations = outcome
        .observations
        .iter()
        .filter(|observation| observation_has_boundary_learning_signal(observation))
        .take(12)
        .map(|observation| observation.trim().to_string())
        .filter(|observation| !observation.is_empty())
        .collect::<Vec<_>>();
    if observations.is_empty() {
        return None;
    }
    Some(format!(
        "boundary-memory job={} success={} reward={:.3} methods={} machineKind={} operationSequence={} assembly={} observations={}",
        outcome.job_id.as_deref().unwrap_or("none"),
        outcome.success,
        outcome.reward,
        outcome.manufacturing_methods.join("+"),
        outcome.machine_kind.as_deref().unwrap_or("none"),
        outcome_operation_sequence_key(outcome)
            .as_deref()
            .unwrap_or("none"),
        outcome.assembly_strategy.as_deref().unwrap_or("none"),
        observations.join("|")
    ))
}

impl LearningRemediationAggregate {
    fn add(&mut self, outcome: &LearningOutcomeRecord) {
        self.samples += 1;
        if !outcome.success {
            self.failures += 1;
        }
        self.reward_sum += outcome.reward;
        self.last_outcome_id = outcome.outcome_id.clone();
        for observation in &outcome.observations {
            if let Some(signal) = remediation_signal(observation) {
                self.observations.insert(signal);
            }
            if let Some(action) = remediation_action_signal(observation) {
                self.recommended_actions.insert(action);
            }
        }
        for note in &outcome.notes {
            if let Some(signal) = remediation_signal(note) {
                self.observations.insert(signal);
            }
            if let Some(action) = remediation_action_signal(note) {
                self.recommended_actions.insert(action);
            }
        }
        if self.recommended_actions.is_empty() {
            self.recommended_actions
                .insert("review-learned-remediation-before-retry".to_string());
        }
    }

    fn risk(
        &self,
        key: String,
        method: String,
        material: Option<String>,
        material_family: Option<String>,
    ) -> LearningRemediationRisk {
        let average_reward = if self.samples == 0 {
            0.0
        } else {
            self.reward_sum / self.samples as f64
        };
        let severity = if self.failures >= 2
            || average_reward <= -1.5
            || self
                .observations
                .iter()
                .any(|signal| signal.contains("machine-failure") || signal.contains("scrap"))
        {
            "high"
        } else {
            "review"
        }
        .to_string();
        let review_action = if severity == "high" {
            format!("avoid-learned-risk-{}", normalize_token(&key))
        } else {
            format!("review-learned-risk-{}", normalize_token(&key))
        };
        LearningRemediationRisk {
            key,
            method,
            material,
            material_family,
            samples: self.samples,
            failures: self.failures,
            average_reward,
            severity,
            review_action,
            observations: self.observations.iter().take(12).cloned().collect(),
            recommended_actions: self.recommended_actions.iter().take(8).cloned().collect(),
            last_outcome_id: self.last_outcome_id.clone(),
        }
    }
}

impl LearningMemory {
    fn new(max_outcomes: usize) -> Self {
        Self {
            outcomes: VecDeque::new(),
            max_outcomes: max_outcomes.max(1),
        }
    }

    fn insert(&mut self, outcome: LearningOutcomeRecord) {
        self.outcomes.push_back(outcome);
        while self.outcomes.len() > self.max_outcomes {
            self.outcomes.pop_front();
        }
    }

    fn count(&self) -> usize {
        self.outcomes.len()
    }

    fn snapshot(&self) -> LearningPolicySnapshot {
        let mut methods = BTreeMap::<String, LearningAggregate>::new();
        let mut method_combinations = BTreeMap::<String, LearningAggregate>::new();
        let mut machine_kinds = BTreeMap::<String, LearningAggregate>::new();
        let mut operation_sequences = BTreeMap::<String, LearningAggregate>::new();
        let mut assemblies = BTreeMap::<String, LearningAggregate>::new();
        let mut remediation_risks = BTreeMap::<
            (String, Option<String>, Option<String>),
            LearningRemediationAggregate,
        >::new();
        let mut successes = 0_u64;
        let mut reward_sum = 0.0;

        for outcome in &self.outcomes {
            if outcome.success {
                successes += 1;
            }
            reward_sum += outcome.reward;
            for method in &outcome.manufacturing_methods {
                methods.entry(method.clone()).or_default().add(outcome);
            }
            if let Some(combination) = method_combination_key(&outcome.manufacturing_methods) {
                method_combinations
                    .entry(combination)
                    .or_default()
                    .add(outcome);
            }
            if let Some(sequence) = outcome_operation_sequence_key(outcome) {
                operation_sequences
                    .entry(sequence)
                    .or_default()
                    .add(outcome);
            }
            if let Some(machine_kind) = outcome.machine_kind.as_ref() {
                let machine_kind = normalize_token(machine_kind);
                if !machine_kind.is_empty() {
                    machine_kinds.entry(machine_kind).or_default().add(outcome);
                }
            }
            if let Some(strategy) = outcome.assembly_strategy.as_ref() {
                assemblies.entry(strategy.clone()).or_default().add(outcome);
            }
            if !outcome.success || outcome.reward < 0.0 {
                let material = outcome
                    .material
                    .as_ref()
                    .map(|material| normalize_token(&material.name));
                let material_family = outcome
                    .material
                    .as_ref()
                    .and_then(|material| material.family.as_ref())
                    .map(|family| normalize_token(family));
                let mut risk_methods = canonical_policy_methods(&outcome.manufacturing_methods);
                if risk_methods.is_empty() {
                    risk_methods = outcome
                        .manufacturing_methods
                        .iter()
                        .map(|method| normalize_token(method))
                        .filter(|method| !method.is_empty())
                        .collect::<BTreeSet<_>>()
                        .into_iter()
                        .collect();
                }
                for method in risk_methods {
                    remediation_risks
                        .entry((method, material.clone(), material_family.clone()))
                        .or_default()
                        .add(outcome);
                }
            }
        }

        let outcome_count = self.outcomes.len();
        let failures = outcome_count as u64 - successes;
        let average_reward = if outcome_count == 0 {
            0.0
        } else {
            reward_sum / outcome_count as f64
        };
        let mut method_preferences = methods
            .into_iter()
            .map(|(key, aggregate)| aggregate.preference(key))
            .collect::<Vec<_>>();
        method_preferences.sort_by(|left, right| {
            right
                .average_reward
                .partial_cmp(&left.average_reward)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| right.samples.cmp(&left.samples))
                .then_with(|| left.key.cmp(&right.key))
        });
        let mut method_combination_preferences = method_combinations
            .into_iter()
            .map(|(key, aggregate)| aggregate.preference(key))
            .collect::<Vec<_>>();
        method_combination_preferences.sort_by(|left, right| {
            right
                .average_reward
                .partial_cmp(&left.average_reward)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| right.samples.cmp(&left.samples))
                .then_with(|| left.key.cmp(&right.key))
        });
        let mut machine_kind_preferences = machine_kinds
            .into_iter()
            .map(|(key, aggregate)| aggregate.preference(key))
            .collect::<Vec<_>>();
        machine_kind_preferences.sort_by(|left, right| {
            right
                .average_reward
                .partial_cmp(&left.average_reward)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| right.samples.cmp(&left.samples))
                .then_with(|| left.key.cmp(&right.key))
        });
        let mut operation_sequence_preferences = operation_sequences
            .into_iter()
            .map(|(key, aggregate)| aggregate.preference(key))
            .collect::<Vec<_>>();
        operation_sequence_preferences.sort_by(|left, right| {
            right
                .average_reward
                .partial_cmp(&left.average_reward)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| right.samples.cmp(&left.samples))
                .then_with(|| left.key.cmp(&right.key))
        });
        let mut assembly_preferences = assemblies
            .into_iter()
            .map(|(key, aggregate)| aggregate.preference(key))
            .collect::<Vec<_>>();
        assembly_preferences.sort_by(|left, right| {
            right
                .average_reward
                .partial_cmp(&left.average_reward)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| right.samples.cmp(&left.samples))
                .then_with(|| left.key.cmp(&right.key))
        });
        let mut remediation_risks = remediation_risks
            .into_iter()
            .map(|((method, material, material_family), aggregate)| {
                let material_key = material
                    .clone()
                    .or_else(|| material_family.clone())
                    .unwrap_or_else(|| "any-material".to_string());
                aggregate.risk(
                    format!("{method}@{material_key}"),
                    method,
                    material,
                    material_family,
                )
            })
            .collect::<Vec<_>>();
        remediation_risks.sort_by(|left, right| {
            right
                .failures
                .cmp(&left.failures)
                .then_with(|| {
                    left.average_reward
                        .partial_cmp(&right.average_reward)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
                .then_with(|| right.samples.cmp(&left.samples))
                .then_with(|| left.key.cmp(&right.key))
        });
        remediation_risks.truncate(16);
        let neural_training_examples = self
            .outcomes
            .iter()
            .rev()
            .take(32)
            .map(|outcome| {
                format!(
                    "job={} success={} reward={:.3} methods={} machineKind={} operationSequence={} assembly={} observations={}",
                    outcome.job_id.as_deref().unwrap_or("none"),
                    outcome.success,
                    outcome.reward,
                    outcome.manufacturing_methods.join("+"),
                    outcome.machine_kind.as_deref().unwrap_or("none"),
                    outcome_operation_sequence_key(outcome)
                        .as_deref()
                        .unwrap_or("none"),
                    outcome.assembly_strategy.as_deref().unwrap_or("none"),
                    outcome.observations.join("|")
                )
            })
            .collect::<Vec<_>>();
        let boundary_learning_examples = self
            .outcomes
            .iter()
            .rev()
            .filter_map(boundary_learning_example)
            .take(32)
            .collect::<Vec<_>>();

        LearningPolicySnapshot {
            outcome_count,
            successes,
            failures,
            average_reward,
            method_preferences,
            method_combination_preferences,
            machine_kind_preferences,
            operation_sequence_preferences,
            assembly_preferences,
            remediation_risks,
            neural_training_examples,
            boundary_learning_examples,
        }
    }
}

fn material_or_default(material: Option<MaterialSpec>) -> Result<MaterialSpec, String> {
    let material = material.unwrap_or(MaterialSpec {
        name: "pla".to_string(),
        family: Some("polymer".to_string()),
        hardness: None,
    });
    Ok(MaterialSpec {
        name: validate_text(&material.name, "material.name", MAX_LABEL_LEN)?,
        family: material
            .family
            .map(|family| validate_text(&family, "material.family", MAX_LABEL_LEN))
            .transpose()?,
        hardness: material
            .hardness
            .map(|hardness| validate_text(&hardness, "material.hardness", MAX_LABEL_LEN))
            .transpose()?,
    })
}

fn is_metal(material: &MaterialSpec) -> bool {
    let name = normalize_token(&material.name);
    let family = material.family.as_deref().map(normalize_token);
    family.as_deref() == Some("metal")
        || matches!(
            name.as_str(),
            "aluminum"
                | "aluminium"
                | "steel"
                | "stainless-steel"
                | "brass"
                | "bronze"
                | "titanium"
                | "copper"
        )
}

fn is_polymer(material: &MaterialSpec) -> bool {
    let name = normalize_token(&material.name);
    let family = material.family.as_deref().map(normalize_token);
    family.as_deref() == Some("polymer")
        || matches!(
            name.as_str(),
            "pla"
                | "petg"
                | "abs"
                | "nylon"
                | "resin"
                | "asa"
                | "pc"
                | "polycarbonate"
                | "hdpe"
                | "pp"
                | "pellet"
                | "granulate"
                | "regrind"
        )
}

fn is_router_material(material: &MaterialSpec) -> bool {
    let name = normalize_token(&material.name);
    let family = material.family.as_deref().map(normalize_token);
    family
        .as_deref()
        .is_some_and(|family| matches!(family, "wood" | "foam" | "plastic" | "polymer"))
        || matches!(
            name.as_str(),
            "wood" | "plywood" | "mdf" | "acrylic" | "foam" | "hdpe" | "polycarbonate"
        )
}

fn wants_resin_printing(value: &str) -> bool {
    let token = normalize_token(value);
    let material_jetting_context = token.contains("material-jet")
        || token.contains("material jet")
        || token.contains("polyjet")
        || token.contains("poly jet")
        || token.contains("mjp")
        || token.contains("multi-jet")
        || token.contains("multi jet")
        || token.contains("photopolymer jet")
        || token.contains("jetted photopolymer")
        || token.contains("digital material");
    !material_jetting_context
        && (token.contains("resin")
            || token.contains("sla")
            || token.contains("msla")
            || token.contains("dlp")
            || token.contains("photopolymer"))
}

