fn machine_class(kind: &str) -> MachineClass {
    let token = normalize_token(kind);
    if token.contains("printer")
        || token.contains("fdm")
        || token.contains("sla")
        || token.contains("sls")
        || wants_multi_material_fdm_printing(&token)
        || wants_paste_extrusion_printing(&token)
        || wants_bound_metal_filament_printing(&token)
        || wants_pellet_fgf_printing(&token)
        || token.contains("material-jet")
        || token.contains("polyjet")
        || token.contains("mjp")
        || token.contains("directed-energy")
        || token_has_ded_segment(&token)
        || token.contains("waam")
        || token.contains("wire-arc-additive")
        || token.contains("laser-cladding")
        || token.contains("composite")
        || token.contains("continuous-fiber")
        || token.contains("carbon-fiber")
        || token.contains("binder-jet")
        || token.contains("binderjet")
        || token.contains("additive")
    {
        MachineClass::Additive
    } else if is_mill_turn_kind(&token) || token.contains("lathe") || token.contains("turn") {
        MachineClass::Lathe
    } else if token.contains("mill") || token.contains("machining-center") {
        MachineClass::Mill
    } else if token.contains("router") {
        MachineClass::Router
    } else if is_sheet_cutter_kind(&token) {
        MachineClass::SheetCut
    } else {
        MachineClass::Other
    }
}

