fn has_tool_center_point_start(line: &str) -> bool {
    strip_comment(line).split_whitespace().any(|token| {
        token == "G43.4"
            || token.starts_with("G43.4H")
            || token.starts_with("G43.4D")
            || token == "G234"
            || token.starts_with("G234H")
            || token.starts_with("G234D")
    })
}

