fn inspect_text_instruction_line(
    raw_line: &str,
    program_id: &str,
    line_number: usize,
    language: &str,
    findings: &mut Vec<ValidationFinding>,
    boundaries: &mut Vec<FailureBoundary>,
    improvements: &mut Vec<InstructionImprovement>,
) -> TextInstructionSignals {
    let mut signals = TextInstructionSignals::default();
    if language_or_line_has_any(
        language,
        raw_line,
        &[
            "slicer",
            "slice",
            "printer-job",
            "print job",
            "3mf",
            "stl",
            "cura",
            "prusa",
            "bambu",
            "superslicer",
            "lychee",
            "chitubox",
        ],
    ) {
        signals.has_slicer_context = true;
    }
    if language_or_line_has_any(
        language,
        raw_line,
        &[
            "profile",
            "preset",
            "nozzle",
            "material profile",
            "filament",
            "resin profile",
            "powder profile",
            "temperature",
            "layer height",
        ],
    ) {
        signals.has_slicer_profile = true;
        signals.has_process_preparation = true;
    }
    if text_has_any(
        raw_line,
        &[
            "orient",
            "orientation",
            "build plate",
            "plate orientation",
            "flat side",
            "rotate",
            "tilt",
            "lay flat",
        ],
    ) {
        signals.has_slicer_orientation = true;
        signals.has_setup_reference = true;
    }
    if text_has_any(
        raw_line,
        &[
            "support",
            "supports",
            "tree support",
            "overhang",
            "bridge",
            "raft",
            "brim",
            "support blocker",
            "drain hole",
        ],
    ) {
        signals.has_slicer_support_plan = true;
    }
    if text_has_any(
        raw_line,
        &[
            "first layer",
            "z offset",
            "bed mesh",
            "bed level",
            "bed leveling",
            "purge",
            "prime line",
            "flow calibration",
            "adhesion",
            "pei",
            "garolite",
            "build surface",
        ],
    ) {
        signals.has_slicer_first_layer_evidence = true;
        signals.has_setup_reference = true;
    }
    if has_text_slicer_mesh_source_context(raw_line) {
        signals.has_slicer_mesh_source_context = true;
        signals.has_setup_reference = true;
    }
    if has_text_slicer_mesh_topology_evidence(raw_line) {
        signals.has_slicer_mesh_topology_evidence = true;
        signals.has_process_preparation = true;
    }
    if has_text_additive_high_speed_context(language, raw_line) {
        signals.has_slicer_high_speed_context = true;
        signals.has_process_preparation = true;
    }
    if has_additive_high_speed_kinematic_evidence(raw_line) {
        signals.has_slicer_high_speed_kinematic_evidence = true;
        signals.has_process_preparation = true;
    }
    let multi_material_fdm_context = has_text_multi_material_fdm_context(language, raw_line);
    if multi_material_fdm_context {
        signals.has_multi_material_fdm_text_context = true;
    }
    if multi_material_fdm_context && has_text_multi_material_fdm_map_evidence(raw_line) {
        signals.has_multi_material_fdm_map_evidence = true;
        signals.has_process_preparation = true;
    }
    if multi_material_fdm_context && has_text_multi_material_fdm_purge_resume_evidence(raw_line) {
        signals.has_multi_material_fdm_purge_resume_evidence = true;
        signals.has_process_preparation = true;
    }
    if text_has_any(
        raw_line,
        &[
            "home",
            "probe",
            "zero",
            "work offset",
            "bed level",
            "level bed",
            "fixture",
            "clamp",
            "vise",
            "stickout",
            "tool length",
        ],
    ) {
        signals.has_setup_reference = true;
        boundaries.push(FailureBoundary {
            kind: "setup-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason: "text instruction depends on setup, fixture, work offset, probing, bed leveling, or tool length state"
                .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "capture setup measurements as explicit preflight data before the machine cycle continues"
                    .to_string(),
        });
    }
    if text_has_any(
        raw_line,
        &[
            "pause",
            "operator",
            "manual",
            "confirm",
            "wait for",
            "remove part",
            "change filament",
            "material change",
            "swap",
            "reload",
        ],
    ) {
        boundaries.push(FailureBoundary {
            kind: "human-intervention".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason: "text instruction requires an operator action, pause, material change, or manual confirmation"
                .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "split this into an operator-approved checkpoint or provide verified automation for the action"
                    .to_string(),
        });
    }
    if text_has_any(
        raw_line,
        &[
            "wash",
            "cure",
            "uv",
            "depowder",
            "sinter",
            "anneal",
            "deburr",
            "remove support",
            "support removal",
            "post process",
            "post-process",
        ],
    ) {
        signals.has_process_preparation = true;
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "text-post-processing-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message: "text instruction requires post-processing outside the primary machine cycle"
                .to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "post-processing-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason: "wash/cure/depowder/sinter/deburr/support-removal steps cannot complete as one uninterrupted machine program"
                .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "model post-processing as its own process step with readiness and inspection gates"
                    .to_string(),
        });
    }
    let resin_context = has_text_resin_context(language, raw_line);
    let resin_print_context = has_text_resin_print_context(language, raw_line);
    let resin_layer_manifest_context = has_text_resin_layer_manifest_context(language, raw_line);
    let resin_postprocess_evidence = has_text_resin_postprocess_evidence(raw_line);
    if resin_context {
        signals.has_resin_context = true;
    }
    if resin_print_context {
        signals.has_resin_print_context = true;
    }
    if resin_layer_manifest_context {
        signals.has_resin_layer_manifest_context = true;
    }
    if resin_context && has_text_resin_profile_evidence(raw_line) {
        signals.has_resin_profile_evidence = true;
        signals.has_process_preparation = true;
    }
    if resin_print_context && has_text_resin_vat_capacity_context(raw_line) {
        signals.has_resin_vat_capacity_context = true;
    }
    if resin_context && has_text_resin_vat_capacity_evidence(raw_line) {
        signals.has_resin_vat_capacity_evidence = true;
        signals.has_process_preparation = true;
    }
    if resin_layer_manifest_context && has_text_resin_layer_manifest_image_evidence(raw_line) {
        signals.has_resin_layer_manifest_image_evidence = true;
        signals.has_process_preparation = true;
    }
    if resin_layer_manifest_context && has_text_resin_layer_manifest_motion_evidence(raw_line) {
        signals.has_resin_layer_manifest_motion_evidence = true;
        signals.has_process_preparation = true;
    }
    if resin_context && resin_postprocess_evidence {
        signals.has_resin_postprocess_evidence = true;
        signals.has_process_preparation = true;
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "text-resin-handling-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message: "resin instruction needs chemical handling, ventilation, wash, cure, or waste controls"
                .to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "resin-handling-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason:
                "SLA/MSLA resin work can leave uncured resin, IPA waste, UV-cure timing, and ventilation/PPE requirements outside the printer cycle"
                    .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "split resin handling into explicit wash, cure, support-removal, waste-containment, PPE, and ventilation checkpoints"
                    .to_string(),
        });
    }
    let material_jetting_context = has_text_material_jetting_context(language, raw_line);
    if material_jetting_context {
        signals.has_material_jetting_text_context = true;
    }
    if material_jetting_context && has_text_material_jetting_material_evidence(raw_line) {
        signals.has_material_jetting_material_evidence = true;
        signals.has_process_preparation = true;
    }
    if material_jetting_context && has_text_material_jetting_support_evidence(raw_line) {
        signals.has_material_jetting_support_evidence = true;
        signals.has_process_preparation = true;
    }
    if material_jetting_context && has_text_material_jetting_uv_inspection_evidence(raw_line) {
        signals.has_material_jetting_uv_inspection_evidence = true;
        signals.has_process_preparation = true;
    }
    let pellet_fgf_context = has_text_pellet_fgf_context(language, raw_line);
    if pellet_fgf_context {
        signals.has_pellet_fgf_text_context = true;
    }
    if pellet_fgf_context && has_text_pellet_fgf_material_evidence(raw_line) {
        signals.has_pellet_fgf_material_evidence = true;
        signals.has_process_preparation = true;
    }
    if pellet_fgf_context && has_text_pellet_fgf_bead_thermal_evidence(raw_line) {
        signals.has_pellet_fgf_bead_thermal_evidence = true;
        signals.has_process_preparation = true;
    }
    let paste_extrusion_context = has_text_paste_extrusion_context(language, raw_line);
    if paste_extrusion_context {
        signals.has_paste_extrusion_text_context = true;
    }
    if paste_extrusion_context && has_text_paste_extrusion_rheology_evidence(raw_line) {
        signals.has_paste_extrusion_rheology_evidence = true;
        signals.has_process_preparation = true;
    }
    if paste_extrusion_context && has_text_paste_extrusion_drying_evidence(raw_line) {
        signals.has_paste_extrusion_drying_evidence = true;
        signals.has_process_preparation = true;
    }
    let bound_metal_fff_context = has_text_bound_metal_fff_context(language, raw_line);
    if bound_metal_fff_context {
        signals.has_bound_metal_fff_text_context = true;
    }
    if bound_metal_fff_context && has_text_bound_metal_fff_profile_evidence(raw_line) {
        signals.has_bound_metal_fff_profile_evidence = true;
        signals.has_process_preparation = true;
    }
    if bound_metal_fff_context && has_text_bound_metal_fff_debind_sinter_evidence(raw_line) {
        signals.has_bound_metal_fff_debind_sinter_evidence = true;
        signals.has_process_preparation = true;
    }
    let ded_context = has_text_ded_context(language, raw_line);
    if ded_context {
        signals.has_ded_text_context = true;
    }
    if ded_context && has_text_ded_feedstock_path_evidence(raw_line) {
        signals.has_ded_feedstock_path_evidence = true;
        signals.has_process_preparation = true;
    }
    if ded_context && has_text_ded_energy_shielding_evidence(raw_line) {
        signals.has_ded_energy_shielding_evidence = true;
        signals.has_process_preparation = true;
    }
    if ded_context && has_text_ded_thermal_inspection_evidence(raw_line) {
        signals.has_ded_thermal_inspection_evidence = true;
        signals.has_process_preparation = true;
    }
    let composite_fiber_context = has_text_composite_fiber_context(language, raw_line);
    if composite_fiber_context {
        signals.has_composite_fiber_text_context = true;
    }
    if composite_fiber_context && has_text_composite_fiber_layup_evidence(raw_line) {
        signals.has_composite_fiber_layup_evidence = true;
        signals.has_process_preparation = true;
    }
    if composite_fiber_context && has_text_composite_fiber_process_evidence(raw_line) {
        signals.has_composite_fiber_process_evidence = true;
        signals.has_process_preparation = true;
    }
    if composite_fiber_context && has_text_composite_fiber_inspection_evidence(raw_line) {
        signals.has_composite_fiber_inspection_evidence = true;
        signals.has_process_preparation = true;
    }
    let powder_context = has_text_powder_bed_context(language, raw_line);
    let powder_print_context = has_text_powder_bed_print_context(language, raw_line);
    let powder_recoater_thermal_context =
        has_text_powder_bed_recoater_thermal_context(language, raw_line);
    let powder_handling_evidence = has_text_powder_bed_handling_evidence(raw_line);
    let binder_jet_context = has_text_binder_jet_context(language, raw_line);
    if powder_context {
        signals.has_powder_bed_context = true;
    }
    if powder_print_context {
        signals.has_powder_bed_print_context = true;
    }
    if powder_recoater_thermal_context {
        signals.has_powder_bed_recoater_thermal_context = true;
    }
    if powder_context && has_text_powder_bed_profile_evidence(raw_line) {
        signals.has_powder_bed_profile_evidence = true;
        signals.has_process_preparation = true;
    }
    if powder_context && has_text_powder_bed_recoater_clearance_evidence(raw_line) {
        signals.has_powder_bed_recoater_clearance_evidence = true;
        signals.has_process_preparation = true;
    }
    if powder_context && has_text_powder_bed_thermal_pack_evidence(raw_line) {
        signals.has_powder_bed_thermal_pack_evidence = true;
        signals.has_process_preparation = true;
    }
    if powder_context && powder_handling_evidence {
        signals.has_powder_bed_handling_evidence = true;
        signals.has_process_preparation = true;
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "text-powder-handling-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message:
                "powder-bed instruction needs cooldown, depowdering, powder recovery, or atmosphere controls"
                    .to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "powder-handling-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason:
                "SLS/MJF powder-bed work can require cooldown dwell, inert/thermal profile checks, grounded depowdering, and powder reuse controls outside one uninterrupted print cycle"
                    .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "split cooldown, depowdering, powder recovery, refresh-ratio, PPE, and atmosphere checks into explicit operator or automation checkpoints"
                    .to_string(),
        });
    }
    if binder_jet_context {
        signals.has_binder_jet_text_context = true;
    }
    if binder_jet_context && has_text_binder_jet_process_evidence(raw_line) {
        signals.has_binder_jet_process_evidence = true;
        signals.has_process_preparation = true;
    }
    if binder_jet_context && has_text_binder_jet_postprocess_evidence(raw_line) {
        signals.has_binder_jet_postprocess_evidence = true;
        signals.has_process_preparation = true;
    }
    if binder_jet_context && has_text_binder_jet_shrinkage_evidence(raw_line) {
        signals.has_binder_jet_shrinkage_evidence = true;
        signals.has_process_preparation = true;
    }
    let subtractive_context = has_text_subtractive_context(language, raw_line);
    if subtractive_context {
        signals.has_subtractive_text_context = true;
    }
    if has_text_subtractive_setup_evidence(raw_line) {
        signals.has_subtractive_text_setup_evidence = true;
        signals.has_setup_reference = true;
    }
    if has_text_subtractive_process_evidence(raw_line) {
        signals.has_subtractive_text_process_evidence = true;
        signals.has_process_preparation = true;
    }
    let mill_turn_text_context = has_text_mill_turn_context(language, raw_line);
    if mill_turn_text_context {
        signals.has_mill_turn_text_context = true;
        signals.has_subtractive_text_context = true;
    }
    if has_text_mill_turn_live_tooling_evidence(raw_line) {
        signals.has_mill_turn_live_tooling_evidence = true;
        signals.has_setup_reference = true;
        signals.has_process_preparation = true;
    }
    let mill_turn_transfer_context = has_text_mill_turn_transfer_context(language, raw_line);
    if mill_turn_transfer_context {
        signals.has_mill_turn_text_context = true;
        signals.has_mill_turn_transfer_context = true;
        signals.has_subtractive_text_context = true;
    }
    if has_text_mill_turn_spindle_transfer_evidence(raw_line) {
        signals.has_mill_turn_spindle_transfer_evidence = true;
        signals.has_setup_reference = true;
        signals.has_process_preparation = true;
    }
    if has_lathe_threading_command(raw_line) {
        signals.has_lathe_text_threading_context = true;
    }
    if has_lathe_threading_feed_mode_evidence(raw_line) {
        signals.has_lathe_text_threading_sync_evidence = true;
        signals.has_process_preparation = true;
    }
    if has_lathe_partoff_command(raw_line) {
        signals.has_lathe_text_partoff_context = true;
    }
    if has_lathe_partoff_support_evidence(raw_line) {
        signals.has_lathe_text_partoff_support_evidence = true;
        signals.has_setup_reference = true;
    }
    let sheet_cutting_text_context = has_text_sheet_cutting_context(language, raw_line);
    if sheet_cutting_text_context {
        signals.has_sheet_cutting_text_context = true;
    }
    if has_text_sheet_cutting_recipe_evidence(raw_line) {
        signals.has_sheet_cutting_recipe_evidence = true;
        signals.has_process_preparation = true;
    }
    let wire_edm_text_context = has_text_wire_edm_context(language, raw_line);
    if wire_edm_text_context {
        signals.has_wire_edm_text_context = true;
        signals.has_sheet_cutting_text_context = true;
    }
    if wire_edm_text_context && has_text_wire_edm_setup_evidence(raw_line) {
        signals.has_wire_edm_setup_evidence = true;
        signals.has_setup_reference = true;
    }
    if wire_edm_text_context && has_text_wire_edm_process_evidence(raw_line) {
        signals.has_wire_edm_process_evidence = true;
        signals.has_process_preparation = true;
    }
    let sinker_edm_text_context = has_text_sinker_edm_context(language, raw_line);
    if sinker_edm_text_context {
        signals.has_sinker_edm_text_context = true;
    }
    if sinker_edm_text_context && has_text_sinker_edm_electrode_evidence(raw_line) {
        signals.has_sinker_edm_electrode_evidence = true;
        signals.has_setup_reference = true;
    }
    if sinker_edm_text_context && has_text_sinker_edm_dielectric_evidence(raw_line) {
        signals.has_sinker_edm_dielectric_evidence = true;
        signals.has_process_preparation = true;
    }
    if sinker_edm_text_context && has_text_sinker_edm_burn_control_evidence(raw_line) {
        signals.has_sinker_edm_burn_control_evidence = true;
        signals.has_process_preparation = true;
    }
    let assembly_context = has_text_assembly_context(language, raw_line);
    if assembly_context {
        signals.has_text_assembly_context = true;
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "text-assembly-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message: "text instruction combines fabricated pieces after machine work".to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "assembly-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason: "instruction requires combining parts, bonding, fastening, or fit-up after fabrication"
                .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "preserve alignment datums and add inspection before the assembly step".to_string(),
        });
    }
    if has_text_assembly_fit_evidence(raw_line) {
        signals.has_text_assembly_fit_evidence = true;
        signals.has_process_preparation = true;
    }
    let assembly_cell_context = has_text_assembly_cell_context(language, raw_line);
    if assembly_cell_context {
        signals.has_text_assembly_cell_context = true;
        signals.has_text_assembly_context = true;
    }
    if assembly_cell_context && has_text_assembly_cell_automation_evidence(raw_line) {
        signals.has_text_assembly_cell_automation_evidence = true;
        signals.has_setup_reference = true;
    }
    if assembly_cell_context && has_text_assembly_join_process_evidence(raw_line) {
        signals.has_text_assembly_join_process_evidence = true;
        signals.has_process_preparation = true;
        signals.has_text_assembly_fit_evidence = true;
    }
    let part_separation_context = has_text_part_separation_context(language, raw_line);
    if part_separation_context {
        signals.has_text_part_separation_context = true;
        signals.has_process_preparation = true;
        findings.push(ValidationFinding {
            severity: "info".to_string(),
            code: "text-part-separation-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message: "text instruction physically separates fabricated pieces after machine work"
                .to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "part-separation-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason:
                "instruction requires cutting, releasing, or separating pieces from a build plate, sprue/tree, tabs, bridges, or nested stock"
                    .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "model part separation as its own operation with cut path, workholding, heat/kerf, deburr, and inspection gates"
                    .to_string(),
        });
    }
    if has_text_part_separation_evidence(raw_line) {
        signals.has_text_part_separation_evidence = true;
        signals.has_setup_reference = true;
        signals.has_process_preparation = true;
    }
    if has_text_precision_requirement_context(language, raw_line) {
        signals.has_text_precision_requirement_context = true;
    }
    if has_text_precision_inspection_evidence(raw_line) {
        signals.has_text_precision_inspection_evidence = true;
        signals.has_process_preparation = true;
    }
    if has_text_unattended_run_context(raw_line) {
        signals.has_text_unattended_run_context = true;
    }
    if has_text_unattended_monitoring_evidence(raw_line) {
        signals.has_text_unattended_monitoring_evidence = true;
        signals.has_process_preparation = true;
    }
    if has_text_thermal_postprocess_context(raw_line) {
        signals.has_text_thermal_postprocess_context = true;
        signals.has_process_preparation = true;
    }
    if has_text_thermal_postprocess_evidence(raw_line) {
        signals.has_text_thermal_postprocess_evidence = true;
        signals.has_process_preparation = true;
    }
    if has_text_surface_finishing_context(raw_line) {
        signals.has_text_surface_finishing_context = true;
        signals.has_process_preparation = true;
    }
    if has_text_surface_finishing_evidence(raw_line) {
        signals.has_text_surface_finishing_evidence = true;
        signals.has_process_preparation = true;
    }
    if has_text_indexed_setup_context(raw_line) {
        signals.has_text_indexed_setup_context = true;
        signals.has_setup_reference = true;
    }
    if has_text_indexed_setup_evidence(raw_line) {
        signals.has_text_indexed_setup_evidence = true;
        signals.has_setup_reference = true;
    }
    if text_has_any(
        raw_line,
        &[
            "split",
            "separate piece",
            "two pieces",
            "multiple pieces",
            "segment",
            "part 1",
            "part 2",
        ],
    ) {
        findings.push(ValidationFinding {
            severity: "info".to_string(),
            code: "text-split-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message: "text instruction separates the object into multiple fabricated pieces"
                .to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "split-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason:
                "instruction indicates the object must be separated into pieces or recombined later"
                    .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "track each piece as a separate operation and make recombination explicit"
                    .to_string(),
        });
    }
    if text_has_any(
        raw_line,
        &["complete", "done", "finish", "finished", "end job"],
    ) {
        signals.has_completion_marker = true;
    }
    if text_has_any(
        raw_line,
        &["ppe", "gloves", "respirator", "ventilation", "enclosure"],
    ) {
        signals.has_process_preparation = true;
    }
    if text_has_any(
        raw_line,
        &[
            "laser",
            "waterjet",
            "water-jet",
            "plasma",
            "kerf",
            "pierce",
            "assist gas",
            "assist-air",
            "fume",
            "fire watch",
            "lens",
            "focus",
        ],
    ) {
        signals.has_process_preparation = true;
        findings.push(ValidationFinding {
            severity: "warning".to_string(),
            code: "text-sheet-cutting-boundary".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message:
                "text instruction depends on sheet-cutting kerf, fire/fume, pierce, or focus state"
                    .to_string(),
        });
        boundaries.push(FailureBoundary {
            kind: "sheet-cutting-boundary".to_string(),
            severity: "warning".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            reason:
                "laser/waterjet/plasma/knife-style sheet work needs kerf, material, focus, fire/fume, and release checks outside an unattended cycle"
                    .to_string(),
            requires_human_intervention: true,
            suggested_resolution:
                "record kerf coupons, material certification, focus/assist-gas settings, ventilation/fire-watch checks, and tab/release inspection"
                    .to_string(),
        });
    }
    if text_has_any(
        raw_line,
        &["proprietary", "vendor only", "unsupported", "unknown"],
    ) {
        findings.push(ValidationFinding {
            severity: "info".to_string(),
            code: "text-controller-specific-step".to_string(),
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            message: "text instruction references a controller/vendor-specific or unknown step"
                .to_string(),
        });
    }
    if language != "setup-sheet" && text_has_any(raw_line, &["checklist", "setup sheet"]) {
        improvements.push(InstructionImprovement {
            program_id: Some(program_id.to_string()),
            line: Some(line_number),
            action: "normalize-text-setup-sheet".to_string(),
            reason:
                "text program includes setup-sheet concepts but is not labelled as a setup sheet"
                    .to_string(),
        });
    }
    signals
}

