fn release_package_process_node_id(
    program_id: Option<&str>,
    part_id: Option<&str>,
    process_graph: &ProcessGraph,
) -> Option<String> {
    process_graph
        .nodes
        .iter()
        .find(|node| {
            program_id.is_some_and(|program| node.program_id.as_deref() == Some(program))
                || part_id.is_some_and(|part| node.part_id == part)
        })
        .map(|node| node.node_id.clone())
}

fn release_package_required_artifacts(
    program_id: Option<&str>,
    design_export_ids: &[String],
    fixture_setup_ids: &[String],
    monitoring_point_ids: &[String],
    quality_inspection_ids: &[String],
    decomposition_target_ids: &[String],
    interface_control_ids: &[String],
    controller_target_ids: &[String],
) -> Vec<String> {
    let mut artifacts = BTreeSet::new();
    artifacts.insert("machine-release".to_string());
    artifacts.insert("manufacturing-handoff".to_string());
    artifacts.insert("design-package".to_string());
    artifacts.insert("design-export-bundle".to_string());
    if let Some(program_id) = program_id {
        artifacts.insert(artifact_id("program", program_id));
    }
    if !design_export_ids.is_empty() {
        artifacts.extend(design_export_ids.iter().cloned());
    }
    if !fixture_setup_ids.is_empty() {
        artifacts.insert("fixture-plan".to_string());
    }
    if !monitoring_point_ids.is_empty() {
        artifacts.insert("monitoring-plan".to_string());
    }
    if !quality_inspection_ids.is_empty() {
        artifacts.insert("quality-plan".to_string());
    }
    if !decomposition_target_ids.is_empty() {
        artifacts.insert("decomposition-plan".to_string());
    }
    if !interface_control_ids.is_empty() {
        artifacts.insert("interface-control-plan".to_string());
    }
    if !controller_target_ids.is_empty() {
        artifacts.insert("controller-plan".to_string());
        artifacts.insert("postprocess-plan".to_string());
    }
    artifacts.into_iter().collect()
}

fn release_package_blockers(
    part_id: Option<&str>,
    program_id: Option<&str>,
    design_exports: &DesignExportBundle,
    fixture_plan: &FixturePlan,
    monitoring_plan: &MonitoringPlan,
    decomposition_plan: &DecompositionPlan,
    interface_control_plan: &InterfaceControlPlan,
    controller_plan: &ControllerPlan,
    machine_release: &MachineReleaseReport,
) -> Vec<String> {
    let mut blockers = BTreeSet::new();
    for blocker in &machine_release.blockers {
        if program_id.is_some_and(|program| blocker.program_id.as_deref() == Some(program)) {
            blockers.insert(format!(
                "machine-release:{}:{}",
                blocker.blocker_type, blocker.reason
            ));
        }
    }
    for export in &design_exports.part_exports {
        if part_id.is_some_and(|part| export.part_id == part)
            || program_id.is_some_and(|program| export.program_id.as_deref() == Some(program))
        {
            blockers.extend(
                export
                    .blockers
                    .iter()
                    .map(|blocker| format!("design-export:{}:{blocker}", export.export_id)),
            );
        }
    }
    for setup in &fixture_plan.setups {
        if part_id.is_some_and(|part| setup.part_id == part)
            || program_id.is_some_and(|program| setup.program_id.as_deref() == Some(program))
        {
            blockers.extend(
                setup
                    .release_blockers
                    .iter()
                    .map(|blocker| format!("fixture:{}:{blocker}", setup.setup_id)),
            );
        }
    }
    for point in &monitoring_plan.monitor_points {
        if part_id.is_some_and(|part| point.part_id == part)
            || program_id.is_some_and(|program| point.program_id.as_deref() == Some(program))
        {
            blockers.extend(
                point
                    .release_blockers
                    .iter()
                    .map(|blocker| format!("monitoring:{}:{blocker}", point.monitor_id)),
            );
        }
    }
    for target in &decomposition_plan.targets {
        if part_id.is_some_and(|part| {
            target.source_part_id.as_deref() == Some(part)
                || target
                    .replacement_part_ids
                    .iter()
                    .any(|replacement| replacement == part)
        }) || program_id.is_some_and(|program| target.program_id.as_deref() == Some(program))
        {
            blockers.extend(
                target
                    .release_blockers
                    .iter()
                    .map(|blocker| format!("decomposition:{}:{blocker}", target.target_id)),
            );
        }
    }
    for control in &interface_control_plan.controls {
        if part_id.is_some_and(|part| control.from_part_id == part || control.to_part_id == part) {
            blockers.extend(
                control
                    .release_blockers
                    .iter()
                    .map(|blocker| format!("interface:{}:{blocker}", control.control_id)),
            );
        }
    }
    for target in &controller_plan.compatibility_targets {
        if program_id.is_some_and(|program| target.program_id == program) {
            blockers.extend(
                target
                    .release_blockers
                    .iter()
                    .map(|blocker| format!("controller:{}:{blocker}", target.target_id)),
            );
        }
    }
    if blockers.is_empty() && machine_release.machine_release_blocked {
        blockers.insert(format!(
            "machine-release-blocked:{}",
            machine_release.status
        ));
    }
    blockers.into_iter().collect()
}

fn release_package_state(release_blockers: &[String], machine_ready: bool) -> String {
    if !release_blockers.is_empty() {
        "release-blocked".to_string()
    } else if machine_ready {
        "machine-ready".to_string()
    } else {
        "release-review-ready".to_string()
    }
}

fn release_package_gates_for_package(package: &ReleasePackage) -> Vec<ReleasePackageGate> {
    let package_token = normalize_token(&package.package_id);
    let blocked = !package.release_blockers.is_empty();
    let review_status = if blocked { "blocked" } else { "pending-review" };
    let mut gates = vec![
        ReleasePackageGate {
            gate_id: format!("release-package-gate-{package_token}-design"),
            package_id: Some(package.package_id.clone()),
            gate_type: "design-export-review".to_string(),
            status: review_status.to_string(),
            required_before: "machine-code-or-operator-traveler-release".to_string(),
            evidence: if package.design_export_ids.is_empty() {
                "design package and parametric-design artifact retained for review".to_string()
            } else {
                format!(
                    "review generated design exports: {}",
                    package.design_export_ids.join(", ")
                )
            },
            release_blocker: blocked,
        },
        ReleasePackageGate {
            gate_id: format!("release-package-gate-{package_token}-setup-quality-monitoring"),
            package_id: Some(package.package_id.clone()),
            gate_type: "setup-quality-monitoring-evidence".to_string(),
            status: review_status.to_string(),
            required_before: "unattended-or-machine-ready-run".to_string(),
            evidence: format!(
                "fixture setups={}, quality inspections={}, monitoring points={}",
                package.fixture_setup_ids.len(),
                package.quality_inspection_ids.len(),
                package.monitoring_point_ids.len()
            ),
            release_blocker: blocked,
        },
        ReleasePackageGate {
            gate_id: format!("release-package-gate-{package_token}-machine-release"),
            package_id: Some(package.package_id.clone()),
            gate_type: "machine-release-signoff".to_string(),
            status: package.release_state.clone(),
            required_before: "machine-ready-release".to_string(),
            evidence: if package.release_blockers.is_empty() {
                "no package-specific blockers retained; operator/controller signoff still required for draft artifacts"
                    .to_string()
            } else {
                package.release_blockers.join(" | ")
            },
            release_blocker: blocked,
        },
    ];
    if !package.controller_target_ids.is_empty() {
        gates.push(ReleasePackageGate {
            gate_id: format!("release-package-gate-{package_token}-controller"),
            package_id: Some(package.package_id.clone()),
            gate_type: "controller-postprocess-compatibility".to_string(),
            status: review_status.to_string(),
            required_before: "controller-load-or-dry-run".to_string(),
            evidence: format!(
                "controller compatibility targets: {}",
                package.controller_target_ids.join(", ")
            ),
            release_blocker: blocked,
        });
    }
    if !package.decomposition_target_ids.is_empty() || !package.interface_control_ids.is_empty() {
        gates.push(ReleasePackageGate {
            gate_id: format!("release-package-gate-{package_token}-split-combine"),
            package_id: Some(package.package_id.clone()),
            gate_type: "split-combine-interface-release".to_string(),
            status: review_status.to_string(),
            required_before: "child-route-or-recomposition-release".to_string(),
            evidence: format!(
                "decomposition targets={}, interface controls={}",
                package.decomposition_target_ids.len(),
                package.interface_control_ids.len()
            ),
            release_blocker: blocked,
        });
    }
    gates
}

fn release_package_for_program(
    program: &GeneratedProgram,
    design_exports: &DesignExportBundle,
    process_graph: &ProcessGraph,
    quality_plan: &QualityPlan,
    fixture_plan: &FixturePlan,
    monitoring_plan: &MonitoringPlan,
    interface_control_plan: &InterfaceControlPlan,
    decomposition_plan: &DecompositionPlan,
    controller_plan: &ControllerPlan,
    machine_release: &MachineReleaseReport,
) -> ReleasePackage {
    let part_id = Some(program.part_id.as_str());
    let program_id = Some(program.program_id.as_str());
    let design_export_ids = release_package_design_export_ids(part_id, program_id, design_exports);
    let fixture_setup_ids = release_package_fixture_setup_ids(part_id, program_id, fixture_plan);
    let monitoring_point_ids =
        release_package_monitoring_point_ids(part_id, program_id, monitoring_plan);
    let quality_inspection_ids =
        release_package_quality_inspection_ids(part_id, program_id, quality_plan);
    let decomposition_target_ids =
        release_package_decomposition_target_ids(part_id, program_id, decomposition_plan);
    let interface_control_ids =
        release_package_interface_control_ids(part_id, interface_control_plan);
    let controller_target_ids = release_package_controller_target_ids(program_id, controller_plan);
    let release_blockers = release_package_blockers(
        part_id,
        program_id,
        design_exports,
        fixture_plan,
        monitoring_plan,
        decomposition_plan,
        interface_control_plan,
        controller_plan,
        machine_release,
    );
    let machine_ready = program.machine_ready
        && release_blockers.is_empty()
        && !machine_release.machine_release_blocked;
    let release_state = release_package_state(&release_blockers, machine_ready);
    let required_artifacts = release_package_required_artifacts(
        program_id,
        &design_export_ids,
        &fixture_setup_ids,
        &monitoring_point_ids,
        &quality_inspection_ids,
        &decomposition_target_ids,
        &interface_control_ids,
        &controller_target_ids,
    );
    let package_id = artifact_id("release-package", &program.program_id);
    ReleasePackage {
        learning_observation: format!("release-package:{}:{release_state}", package_id),
        package_id,
        package_kind: "machine-program-release".to_string(),
        part_id: Some(program.part_id.clone()),
        program_id: Some(program.program_id.clone()),
        machine_id: Some(program.machine_id.clone()),
        machine_kind: Some(program.machine_kind.clone()),
        process_node_id: release_package_process_node_id(program_id, part_id, process_graph),
        controller_target_ids,
        design_export_ids,
        fixture_setup_ids,
        monitoring_point_ids,
        quality_inspection_ids,
        decomposition_target_ids,
        interface_control_ids,
        required_artifacts,
        release_blockers,
        release_state,
        machine_ready,
        requires_human_review: !machine_ready,
    }
}

fn assembly_release_package(
    design_exports: &DesignExportBundle,
    quality_plan: &QualityPlan,
    fixture_plan: &FixturePlan,
    monitoring_plan: &MonitoringPlan,
    interface_control_plan: &InterfaceControlPlan,
    decomposition_plan: &DecompositionPlan,
    machine_release: &MachineReleaseReport,
) -> Option<ReleasePackage> {
    if design_exports.assembly_exports.is_empty()
        && interface_control_plan.controls.is_empty()
        && decomposition_plan.recomposition_interfaces.is_empty()
    {
        return None;
    }
    let mut part_ids = BTreeSet::new();
    for control in &interface_control_plan.controls {
        part_ids.insert(control.from_part_id.clone());
        part_ids.insert(control.to_part_id.clone());
    }
    for interface in &decomposition_plan.recomposition_interfaces {
        part_ids.insert(interface.from_part_id.clone());
        part_ids.insert(interface.to_part_id.clone());
    }

    let design_export_ids = design_exports
        .assembly_exports
        .iter()
        .map(|export| export.export_id.clone())
        .collect::<Vec<_>>();
    let fixture_setup_ids = fixture_plan
        .setups
        .iter()
        .filter(|setup| part_ids.contains(&setup.part_id))
        .map(|setup| setup.setup_id.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let monitoring_point_ids = monitoring_plan
        .monitor_points
        .iter()
        .filter(|point| part_ids.contains(&point.part_id))
        .map(|point| point.monitor_id.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let quality_inspection_ids = quality_plan
        .inspection_points
        .iter()
        .filter(|point| part_ids.contains(&point.part_id))
        .map(|point| point.inspection_id.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let decomposition_target_ids = decomposition_plan
        .targets
        .iter()
        .filter(|target| {
            target.target_kind.contains("combine")
                || target.target_kind.contains("recomposition")
                || target
                    .source_part_id
                    .as_ref()
                    .is_some_and(|part| part_ids.contains(part))
                || target
                    .replacement_part_ids
                    .iter()
                    .any(|part| part_ids.contains(part))
        })
        .map(|target| target.target_id.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let interface_control_ids = interface_control_plan
        .controls
        .iter()
        .map(|control| control.control_id.clone())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect::<Vec<_>>();
    let mut release_blockers = BTreeSet::new();
    for export in &design_exports.assembly_exports {
        release_blockers.extend(
            export
                .blockers
                .iter()
                .map(|blocker| format!("assembly-design-export:{}:{blocker}", export.export_id)),
        );
    }
    for control in &interface_control_plan.controls {
        release_blockers.extend(
            control
                .release_blockers
                .iter()
                .map(|blocker| format!("interface:{}:{blocker}", control.control_id)),
        );
    }
    for target in &decomposition_plan.targets {
        release_blockers.extend(
            target
                .release_blockers
                .iter()
                .map(|blocker| format!("decomposition:{}:{blocker}", target.target_id)),
        );
    }
    if release_blockers.is_empty() && machine_release.machine_release_blocked {
        release_blockers.insert(format!(
            "machine-release-blocked:{}",
            machine_release.status
        ));
    }
    let release_blockers = release_blockers.into_iter().collect::<Vec<_>>();
    let machine_ready = release_blockers.is_empty() && !machine_release.machine_release_blocked;
    let release_state = release_package_state(&release_blockers, machine_ready);
    let mut required_artifacts = BTreeSet::from([
        "assembly-plan".to_string(),
        "design-package".to_string(),
        "design-export-bundle".to_string(),
        "interface-control-plan".to_string(),
        "decomposition-plan".to_string(),
        "machine-release".to_string(),
    ]);
    required_artifacts.extend(design_export_ids.iter().cloned());
    if !fixture_setup_ids.is_empty() {
        required_artifacts.insert("fixture-plan".to_string());
    }
    if !monitoring_point_ids.is_empty() {
        required_artifacts.insert("monitoring-plan".to_string());
    }
    if !quality_inspection_ids.is_empty() {
        required_artifacts.insert("quality-plan".to_string());
    }
    let package_id = "release-package-assembly-recomposition".to_string();
    Some(ReleasePackage {
        learning_observation: format!("release-package:{}:{release_state}", package_id),
        package_id,
        package_kind: "assembly-recomposition-release".to_string(),
        part_id: None,
        program_id: None,
        machine_id: None,
        machine_kind: Some("assembly-or-manual-cell".to_string()),
        process_node_id: None,
        controller_target_ids: Vec::new(),
        design_export_ids,
        fixture_setup_ids,
        monitoring_point_ids,
        quality_inspection_ids,
        decomposition_target_ids,
        interface_control_ids,
        required_artifacts: required_artifacts.into_iter().collect(),
        release_blockers,
        release_state,
        machine_ready,
        requires_human_review: true,
    })
}

fn release_package_plan(
    generated_programs: &[GeneratedProgram],
    design_exports: &DesignExportBundle,
    process_graph: &ProcessGraph,
    quality_plan: &QualityPlan,
    fixture_plan: &FixturePlan,
    monitoring_plan: &MonitoringPlan,
    interface_control_plan: &InterfaceControlPlan,
    decomposition_plan: &DecompositionPlan,
    controller_plan: &ControllerPlan,
    machine_release: &MachineReleaseReport,
) -> ReleasePackagePlan {
    let mut packages = generated_programs
        .iter()
        .map(|program| {
            release_package_for_program(
                program,
                design_exports,
                process_graph,
                quality_plan,
                fixture_plan,
                monitoring_plan,
                interface_control_plan,
                decomposition_plan,
                controller_plan,
                machine_release,
            )
        })
        .collect::<Vec<_>>();
    if let Some(assembly_package) = assembly_release_package(
        design_exports,
        quality_plan,
        fixture_plan,
        monitoring_plan,
        interface_control_plan,
        decomposition_plan,
        machine_release,
    ) {
        packages.push(assembly_package);
    }

    let release_gates = packages
        .iter()
        .flat_map(release_package_gates_for_package)
        .collect::<Vec<_>>();
    let ready_package_count = packages
        .iter()
        .filter(|package| package.release_blockers.is_empty())
        .count();
    let blocked_package_count = packages.len().saturating_sub(ready_package_count);
    let machine_release_blocked =
        machine_release.machine_release_blocked || blocked_package_count > 0;
    let status = if machine_release_blocked {
        "release-package-blocked"
    } else if packages.iter().all(|package| package.machine_ready) {
        "machine-ready"
    } else {
        "release-package-review-ready"
    };
    let mut required_artifacts = BTreeSet::from(["release-package-plan".to_string()]);
    for package in &packages {
        required_artifacts.extend(package.required_artifacts.iter().cloned());
    }
    let mut learning_observations = BTreeSet::new();
    learning_observations.insert(format!("release-package-status:{status}"));
    learning_observations.insert(format!("release-package-count:{}", packages.len()));
    learning_observations.extend(
        packages
            .iter()
            .map(|package| package.learning_observation.clone()),
    );
    if blocked_package_count > 0 {
        learning_observations.insert(format!("release-package-blocked:{blocked_package_count}"));
    }

    ReleasePackagePlan {
        schema_version: "dd.fabrication.release-package-plan.v1",
        status: status.to_string(),
        machine_release_blocked,
        package_count: packages.len(),
        ready_package_count,
        blocked_package_count,
        packages,
        release_gates,
        required_artifacts: required_artifacts.into_iter().collect(),
        learning_observations: learning_observations.into_iter().collect(),
        notes: vec![
            "Release packages bundle each machine program or assembly handoff with the design exports, controller targets, setup, quality, monitoring, split/combine, and blocker evidence needed by downstream review workers".to_string(),
            "Packages are draft release packets; machine-ready status remains false until controller/postprocessor checks, simulation or dry-run evidence, profile evidence, and operator or automation signoff clear all gates".to_string(),
            "Learning observations let MDP/POMDP/neural workers compare which package evidence cleared or blocked print, mill, lathe, sheet-cut, EDM, and assembly routes".to_string(),
        ],
    }
}

fn release_package_plan_learning_actions(plan: &ReleasePackagePlan) -> Vec<String> {
    let mut actions = Vec::new();
    for package in &plan.packages {
        let package_token = normalize_token(&package.package_id);
        if package.release_blockers.is_empty() {
            actions.push(format!("verify-release-package-{package_token}"));
        } else {
            actions.push(format!("clear-release-package-{package_token}"));
        }
    }
    actions.extend(plan.release_gates.iter().map(|gate| {
        let gate_token = normalize_token(&gate.gate_id);
        if gate.release_blocker {
            format!("clear-release-package-gate-{gate_token}")
        } else {
            format!("verify-release-package-gate-{gate_token}")
        }
    }));
    actions.sort();
    actions.dedup();
    actions
}

fn stock_strategy_for_part(part: &PartPlan) -> String {
    match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => {
            "resin build envelope with reviewed orientation, drain paths, supports, wash, and cure allowances"
                .to_string()
        }
        MachineClass::Additive if is_powder_bed_printer_kind(&part.machine_kind) => {
            "powder-bed nesting envelope with thermal spacing, cooldown allowance, and depowder access"
                .to_string()
        }
        MachineClass::Additive => {
            "filament build envelope with material profile, support strategy, and bed adhesion margin"
                .to_string()
        }
        MachineClass::Mill if is_rotary_index_mill_kind(&part.machine_kind) => {
            "squared or turned stock in a rotary/indexer fixture with A-axis centerline, clearance, and re-probe allowance"
                .to_string()
        }
        MachineClass::Mill if is_horizontal_mill_kind(&part.machine_kind) => {
            "squared stock on tombstone or side-milling fixture with arbor and cutter-width clearance"
                .to_string()
        }
        MachineClass::Mill => {
            "squared stock with roughing allowance, finish allowance, and probed work offset"
                .to_string()
        }
        MachineClass::Lathe => {
            "round bar or turned blank with chuck/grip allowance and cutoff stock".to_string()
        }
        MachineClass::Router => {
            "sheet or panel stock on spoilboard with tabs, hold-down margin, and dust extraction"
                .to_string()
        }
        MachineClass::SheetCut => {
            "sheet stock with kerf coupon, lead-ins, retained tabs, and part-catch allowance".to_string()
        }
        MachineClass::Other => {
            "operator-defined stock and material certificate before special-process programming"
                .to_string()
        }
    }
}

fn material_feedstock_kind(part: &PartPlan) -> &'static str {
    match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => "photopolymer-resin",
        MachineClass::Additive if is_metal_pbf_printer_kind(&part.machine_kind) => {
            "qualified-metal-powder-lot"
        }
        MachineClass::Additive if is_multi_material_fdm_printer_kind(&part.machine_kind) => {
            "multi-filament-spool-set"
        }
        MachineClass::Additive if is_paste_extrusion_printer_kind(&part.machine_kind) => {
            "paste-or-clay-feedstock"
        }
        MachineClass::Additive if is_powder_bed_printer_kind(&part.machine_kind) => {
            "polymer-powder-lot"
        }
        MachineClass::Additive if is_composite_fiber_printer_kind(&part.machine_kind) => {
            "matrix-material-and-fiber-spool"
        }
        MachineClass::Additive if wants_directed_energy_deposition(&part.machine_kind) => {
            "wire-or-powder-feedstock"
        }
        MachineClass::Additive if is_material_jetting_printer_kind(&part.machine_kind) => {
            "material-and-support-cartridges"
        }
        MachineClass::Additive if is_pellet_fgf_printer_kind(&part.machine_kind) => {
            "pellet-feedstock"
        }
        MachineClass::Additive => "filament-spool",
        MachineClass::Lathe => "round-bar-or-tube-stock",
        MachineClass::Mill | MachineClass::Router => "block-plate-or-sheet-blank",
        MachineClass::SheetCut => "sheet-plate-or-panel",
        MachineClass::Other => "operator-declared-material-kit",
    }
}

fn material_requirement_unit(part: &PartPlan) -> &'static str {
    match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => "ml",
        MachineClass::Additive
            if is_powder_bed_printer_kind(&part.machine_kind)
                || is_metal_pbf_printer_kind(&part.machine_kind) =>
        {
            "cm3"
        }
        MachineClass::Additive => "g",
        MachineClass::Lathe => "mm blank length",
        MachineClass::Mill | MachineClass::Router | MachineClass::SheetCut => "blank",
        MachineClass::Other => "kit",
    }
}

fn material_estimated_quantity(part: &PartPlan, quantity: u32) -> f64 {
    let base_quantity = match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => 35.0,
        MachineClass::Additive if is_metal_pbf_printer_kind(&part.machine_kind) => 55.0,
        MachineClass::Additive if is_powder_bed_printer_kind(&part.machine_kind) => 45.0,
        MachineClass::Additive if is_composite_fiber_printer_kind(&part.machine_kind) => 90.0,
        MachineClass::Additive if wants_directed_energy_deposition(&part.machine_kind) => 180.0,
        MachineClass::Additive if is_material_jetting_printer_kind(&part.machine_kind) => 40.0,
        MachineClass::Additive if is_multi_material_fdm_printer_kind(&part.machine_kind) => 140.0,
        MachineClass::Additive if is_paste_extrusion_printer_kind(&part.machine_kind) => 600.0,
        MachineClass::Additive if is_pellet_fgf_printer_kind(&part.machine_kind) => 450.0,
        MachineClass::Additive => 85.0,
        MachineClass::Lathe => 120.0,
        MachineClass::Mill
        | MachineClass::Router
        | MachineClass::SheetCut
        | MachineClass::Other => 1.0,
    };
    rounded_score(base_quantity * quantity.max(1) as f64)
}

fn material_scrap_allowance_pct(part: &PartPlan) -> f64 {
    let allowance = match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_metal_pbf_printer_kind(&part.machine_kind) => 35.0,
        MachineClass::Additive if is_powder_bed_printer_kind(&part.machine_kind) => 25.0,
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => 20.0,
        MachineClass::Additive if wants_directed_energy_deposition(&part.machine_kind) => 30.0,
        MachineClass::Additive if is_multi_material_fdm_printer_kind(&part.machine_kind) => 22.0,
        MachineClass::Additive if is_paste_extrusion_printer_kind(&part.machine_kind) => 25.0,
        MachineClass::Additive => 15.0,
        MachineClass::Lathe => 20.0,
        MachineClass::Mill | MachineClass::Router => 18.0,
        MachineClass::SheetCut => 12.0,
        MachineClass::Other => 10.0,
    };
    rounded_score(allowance)
}

fn material_conditioning(part: &PartPlan) -> Vec<String> {
    let mut conditioning = match machine_class(&part.machine_kind) {
        MachineClass::Additive if is_resin_printer_kind(&part.machine_kind) => vec![
            "mix resin and verify batch age before fill".to_string(),
            "confirm vat film, drain orientation, wash, and cure compatibility".to_string(),
        ],
        MachineClass::Additive if is_metal_pbf_printer_kind(&part.machine_kind) => vec![
            "verify metal powder lot, sieve state, refresh ratio, and inert handling log"
                .to_string(),
            "reserve cooldown, depowder, and powder recovery controls".to_string(),
        ],
        MachineClass::Additive if is_powder_bed_printer_kind(&part.machine_kind) => vec![
            "verify powder lot, refresh ratio, humidity, and thermal pack spacing".to_string(),
            "reserve cooldown and depowder handling before release".to_string(),
        ],
        MachineClass::Additive if is_composite_fiber_printer_kind(&part.machine_kind) => vec![
            "load matrix material and verify continuous-fiber spool path".to_string(),
            "confirm fiber cutoff, compaction, and cure/post-cure expectations".to_string(),
        ],
        MachineClass::Additive if wants_directed_energy_deposition(&part.machine_kind) => vec![
            "verify wire or powder feed path, shielding gas, and deposition head calibration"
                .to_string(),
            "confirm preheat, interpass, and thermal inspection plan".to_string(),
        ],
        MachineClass::Additive if is_material_jetting_printer_kind(&part.machine_kind) => vec![
            "verify model and support cartridge levels plus purge/wipe station state".to_string(),
            "confirm UV lamp exposure and support-removal compatibility".to_string(),
        ],
        MachineClass::Additive if is_multi_material_fdm_printer_kind(&part.machine_kind) => vec![
            "dry or condition each filament spool and verify slot/material/color map".to_string(),
            "confirm AMS/MMU/IDEX/toolchanger state, purge tower or wipe tower, prime volume, runout sensors, and resume G92 evidence"
                .to_string(),
        ],
        MachineClass::Additive if is_paste_extrusion_printer_kind(&part.machine_kind) => vec![
            "condition paste or clay batch, deair, and verify rheology/slump before loading"
                .to_string(),
            "confirm nozzle, syringe/ram or auger pressure, bead coupon, drying, shrinkage, and green-part support plan"
                .to_string(),
        ],
        MachineClass::Additive if is_pellet_fgf_printer_kind(&part.machine_kind) => vec![
            "dry pellet feedstock to material profile and verify hopper refill capacity"
                .to_string(),
            "confirm screw purge, bead thermal window, and trim allowance".to_string(),
        ],
        MachineClass::Additive => vec![
            "dry or condition filament to material profile".to_string(),
            "verify spool mass, diameter profile, nozzle compatibility, and runout handling"
                .to_string(),
        ],
        MachineClass::Lathe => vec![
            "cut blank with chuck/grip and cutoff allowance".to_string(),
            "verify bar straightness, OD, stick-out, and support requirements".to_string(),
        ],
        MachineClass::Mill => vec![
            "saw or square stock with roughing and finish allowance".to_string(),
            "verify stock thickness, datum access, and workholding clamp clearance".to_string(),
        ],
        MachineClass::Router => vec![
            "verify sheet flatness, spoilboard state, tab margin, and hold-down compatibility"
                .to_string(),
            "stage dust extraction and chip evacuation for the material".to_string(),
        ],
        MachineClass::SheetCut => vec![
            "verify sheet thickness, flatness, kerf coupon area, retained tabs, and part catch"
                .to_string(),
            "stage process support such as gas, abrasive, fume extraction, water table, or slats"
                .to_string(),
        ],
        MachineClass::Other => vec![
            "operator-defined material handling, conditioning, and safety evidence".to_string(),
        ],
    };
    let material_token = normalize_token(&part.material.name);
    if summary_text_has_any(
        &material_token,
        &[
            "nylon",
            "pa",
            "petg",
            "abs",
            "asa",
            "pc",
            "polycarbonate",
            "tpu",
        ],
    ) && !conditioning
        .iter()
        .any(|item| normalize_token(item).contains("dry"))
    {
        conditioning.push("dry hygroscopic polymer feedstock before release".to_string());
    }
    conditioning.sort();
    conditioning.dedup();
    conditioning
}

fn material_required_evidence(part: &PartPlan) -> Vec<String> {
    let mut evidence = vec![
        "material lot, certificate, or operator-declared equivalent".to_string(),
        "available quantity covers planned quantity plus scrap allowance".to_string(),
        "material is compatible with selected machine, process, and safety controls".to_string(),
    ];
    match machine_class(&part.machine_kind) {
        MachineClass::Additive => {
            evidence.push("printer material profile, temperature/exposure settings, and feedstock level/runout evidence".to_string());
            evidence.push(
                "support, adhesion, purge/prime, or build-media readiness evidence".to_string(),
            );
        }
        MachineClass::Mill | MachineClass::Router => {
            evidence.push(
                "blank or sheet size with roughing allowance and verified datum access".to_string(),
            );
            evidence.push(
                "workholding, clamp clearance, and chip/dust evacuation evidence".to_string(),
            );
        }
        MachineClass::Lathe => {
            evidence.push(
                "bar/blank diameter, length, stick-out, grip allowance, and support evidence"
                    .to_string(),
            );
            evidence.push("tool, cutoff, catcher/subspindle/tailstock, or part-support evidence when applicable".to_string());
        }
        MachineClass::SheetCut => {
            evidence.push(
                "sheet thickness, cut-chart/kerf coupon, and retained-tab evidence".to_string(),
            );
            evidence.push(
                "process support media, fume/fire controls, and part-catch evidence".to_string(),
            );
        }
        MachineClass::Other => {
            evidence.push(
                "operator material handling and process-specific release signoff".to_string(),
            );
        }
    }
    evidence.sort();
    evidence.dedup();
    evidence
}

fn boundary_is_material_related(boundary: &FailureBoundary) -> bool {
    let combined = format!(
        "{} {} {}",
        boundary.kind, boundary.reason, boundary.suggested_resolution
    );
    summary_text_has_any(
        &combined,
        &[
            "abrasive",
            "bar",
            "bed",
            "blank",
            "certificate",
            "coolant",
            "datum",
            "feedstock",
            "filament",
            "fixture",
            "gas",
            "heat",
            "kerf",
            "lot",
            "material",
            "nozzle",
            "pellet",
            "powder",
            "resin",
            "sheet",
            "slat",
            "stock",
            "support",
            "temperature",
            "waterjet",
            "workholding",
        ],
    )
}

fn material_boundary_applies(boundary: &FailureBoundary, part: &PartPlan) -> bool {
    if !boundary_is_material_related(boundary) {
        return false;
    }
    let combined = normalize_token(&format!(
        "{} {} {} {}",
        boundary.kind,
        boundary.reason,
        boundary.suggested_resolution,
        boundary.program_id.as_deref().unwrap_or_default()
    ));
    [
        part.id.as_str(),
        part.role.as_str(),
        part.machine_kind.as_str(),
        part.manufacturing_method.as_str(),
        part.material.name.as_str(),
    ]
    .iter()
    .any(|value| combined.contains(&normalize_token(value)))
        || boundary.program_id.is_none()
}

fn material_plan(
    material: &MaterialSpec,
    stock: Option<&StockSpec>,
    quantity: u32,
    parts: &[PartPlan],
    validation: &ValidationReport,
    machine_release: &MachineReleaseReport,
) -> MaterialPlan {
    let material_boundary_count = validation
        .failure_boundaries
        .iter()
        .filter(|boundary| boundary_is_material_related(boundary))
        .count();
    let machine_release_material_blockers = machine_release
        .blockers
        .iter()
        .filter(|blocker| {
            summary_text_has_any(
                &format!(
                    "{} {} {}",
                    blocker.blocker_type, blocker.reason, blocker.required_action
                ),
                &[
                    "material",
                    "stock",
                    "feedstock",
                    "workholding",
                    "fixture",
                    "support",
                    "temperature",
                    "gas",
                    "abrasive",
                    "coolant",
                    "fume",
                ],
            )
        })
        .count();

    let route_requirements = parts
        .iter()
        .map(|part| {
            let mut release_blockers = validation
                .failure_boundaries
                .iter()
                .filter(|boundary| material_boundary_applies(boundary, part))
                .map(|boundary| {
                    format!(
                        "{}: {} -> {}",
                        boundary.kind, boundary.reason, boundary.suggested_resolution
                    )
                })
                .collect::<Vec<_>>();
            if stock.is_none()
                && matches!(
                    machine_class(&part.machine_kind),
                    MachineClass::Mill
                        | MachineClass::Lathe
                        | MachineClass::Router
                        | MachineClass::SheetCut
                )
            {
                release_blockers.push(
                    "declared stock dimensions/form required before subtractive or sheet-cutting machine release"
                        .to_string(),
                );
            }
            if machine_release.machine_release_blocked && machine_release_material_blockers > 0 {
                release_blockers.push(
                    "machine-release blockers include material, support-media, fixture, or process-state evidence"
                        .to_string(),
                );
            }
            release_blockers.sort();
            release_blockers.dedup();

            let feedstock_kind = material_feedstock_kind(part).to_string();
            let learning_observation = format!(
                "material-route:{}:{}:{}",
                normalize_token(&part.id),
                normalize_token(&feedstock_kind),
                normalize_token(&part.machine_kind)
            );

            MaterialRouteRequirement {
                requirement_id: format!("material-{}", normalize_token(&part.id)),
                part_id: part.id.clone(),
                machine_kind: part.machine_kind.clone(),
                manufacturing_method: part.manufacturing_method.clone(),
                feedstock_kind,
                stock_form: stock
                    .map(|stock| stock.form.clone())
                    .unwrap_or_else(|| stock_strategy_for_part(part)),
                estimated_quantity: material_estimated_quantity(part, quantity),
                unit: material_requirement_unit(part).to_string(),
                scrap_allowance_pct: material_scrap_allowance_pct(part),
                conditioning: material_conditioning(part),
                required_evidence: material_required_evidence(part),
                release_blockers,
                learning_observation,
            }
        })
        .collect::<Vec<_>>();

    let mut release_gates = vec![
        "material/stock lot and compatibility evidence reviewed".to_string(),
        "quantity and scrap allowance reserved before dispatch".to_string(),
        "conditioning and support-media readiness captured before machine release".to_string(),
    ];
    if material_boundary_count > 0 {
        release_gates.push(
            "material-related failure boundaries resolved or accepted by reviewer".to_string(),
        );
    }
    if machine_release_material_blockers > 0 {
        release_gates
            .push("machine-release material blockers cleared before ready state".to_string());
    }
    release_gates.sort();
    release_gates.dedup();

    let mut learning_observations = route_requirements
        .iter()
        .map(|requirement| requirement.learning_observation.clone())
        .collect::<Vec<_>>();
    if material_boundary_count > 0 {
        learning_observations.push(format!(
            "material-boundary-count:{}",
            material_boundary_count
        ));
    }
    learning_observations.sort();
    learning_observations.dedup();

    let release_blocked = route_requirements
        .iter()
        .any(|requirement| !requirement.release_blockers.is_empty());
    let status = if release_blocked {
        "material-blocked"
    } else if material_boundary_count > 0 || machine_release_material_blockers > 0 {
        "material-review-required"
    } else {
        "material-planned"
    };

    MaterialPlan {
        schema_version: "dd.fabrication.material-plan.v1",
        status: status.to_string(),
        review_required: true,
        material: material.clone(),
        declared_stock: stock.cloned(),
        route_requirements,
        release_gates,
        learning_observations,
        notes: vec![
            "Material quantities are advisory planning estimates until CAD mass properties, nesting, slicer, or CAM stock models are finalized".to_string(),
            "Machine-ready release still requires human-reviewed material, stock, feedstock, and support-media evidence".to_string(),
        ],
    }
}

fn datum_scheme_for_part(part: &PartPlan) -> Vec<String> {
    match machine_class(&part.machine_kind) {
        MachineClass::Additive => vec![
            "build-plate-z".to_string(),
            "front-left-origin".to_string(),
            "first-layer-witness".to_string(),
        ],
        MachineClass::Mill if is_rotary_index_mill_kind(&part.machine_kind) => vec![
            "G54 rotary centerline".to_string(),
            "A-axis zero/index stop".to_string(),
            "re-probed indexed face datum".to_string(),
        ],
        MachineClass::Mill if is_horizontal_mill_kind(&part.machine_kind) => vec![
            "G54 tombstone or fixture origin".to_string(),
            "machined side-face datum".to_string(),
            "keyway centerline".to_string(),
        ],
        MachineClass::Mill => vec![
            "G54 stock corner or probe origin".to_string(),
            "machined datum face".to_string(),
            "critical feature centerline".to_string(),
        ],
        MachineClass::Lathe => vec![
            "spindle centerline".to_string(),
            "faced Z0 datum".to_string(),
            "measured finish diameter".to_string(),
        ],
        MachineClass::Router | MachineClass::SheetCut => vec![
            "sheet lower-left origin".to_string(),
            "material top surface".to_string(),
            "kerf/test coupon datum".to_string(),
        ],
        MachineClass::Other => vec![
            "operator-declared primary datum".to_string(),
            "operator-declared inspection datum".to_string(),
        ],
    }
}

