fn record_plan_metrics(state: &AppState, response: &FabricationPlanResponse) {
    state
        .metrics
        .generated_programs_total
        .fetch_add(response.generated_programs.len() as u64, Ordering::Relaxed);
    state
        .metrics
        .validation_findings_total
        .fetch_add(response.validation.findings.len() as u64, Ordering::Relaxed);
    state.metrics.failure_boundaries_total.fetch_add(
        response.validation.failure_boundaries.len() as u64,
        Ordering::Relaxed,
    );
    state.metrics.operator_actions_total.fetch_add(
        response
            .operator_intervention_plan
            .required_operator_actions
            .len() as u64,
        Ordering::Relaxed,
    );
    let fixture_release_blockers = response
        .fixture_plan
        .setups
        .iter()
        .map(|setup| setup.release_blockers.len())
        .sum::<usize>()
        + response
            .fixture_plan
            .datum_transfers
            .iter()
            .filter(|transfer| transfer.release_blocker.is_some())
            .count();
    state
        .metrics
        .fixture_release_blockers_total
        .fetch_add(fixture_release_blockers as u64, Ordering::Relaxed);
    let split_combine_reviews = response
        .operator_intervention_plan
        .split_combine_reviews
        .len()
        + response.hybrid_make_plan.split_combine_decisions.len();
    state
        .metrics
        .split_combine_reviews_total
        .fetch_add(split_combine_reviews as u64, Ordering::Relaxed);
}

fn record_analysis_metrics(state: &AppState, response: &InstructionAnalysisResponse) {
    state
        .metrics
        .validation_findings_total
        .fetch_add(response.validation.findings.len() as u64, Ordering::Relaxed);
    state.metrics.failure_boundaries_total.fetch_add(
        response.validation.failure_boundaries.len() as u64,
        Ordering::Relaxed,
    );
    state.metrics.operator_actions_total.fetch_add(
        response
            .operator_intervention_plan
            .required_operator_actions
            .len() as u64,
        Ordering::Relaxed,
    );
    state.metrics.split_combine_reviews_total.fetch_add(
        response
            .operator_intervention_plan
            .split_combine_reviews
            .len() as u64,
        Ordering::Relaxed,
    );
}

fn discriminator_requests_analysis(token: &str) -> bool {
    token.contains("analysis")
        || token.contains("analyze")
        || token.contains("validator")
        || token.contains("validation")
        || (token.contains("instruction") && !token.contains("plan"))
}

fn discriminator_requests_fabrication_outcome(token: &str) -> bool {
    token.contains("observe")
        || token.contains("observation")
        || (token.contains("fabrication") && token.contains("outcome"))
}

fn discriminator_requests_learning_outcome(token: &str) -> bool {
    token.contains("learning-outcome")
        || token.contains("learning-outcomes")
        || token.contains("outcome-record")
        || token.contains("policy-outcome")
        || (token.contains("learning") && token.contains("reward"))
}

fn discriminator_requests_plan(token: &str) -> bool {
    token.contains("plan") || token.contains("fabrication-request")
}

fn parse_analysis_nats_value(value: Value) -> Result<InstructionAnalysisRequest, String> {
    serde_json::from_value(value)
        .map_err(|error| format!("invalid instruction analysis request: {error}"))
}

fn parse_plan_nats_value(value: Value) -> Result<FabricationPlanRequest, String> {
    serde_json::from_value(value)
        .map_err(|error| format!("invalid fabrication plan request: {error}"))
}

fn parse_fabrication_outcome_nats_value(value: Value) -> Result<FabricationOutcomeRequest, String> {
    serde_json::from_value(value)
        .map_err(|error| format!("invalid fabrication outcome request: {error}"))
}

fn parse_learning_outcome_nats_value(value: Value) -> Result<LearningOutcomeRequest, String> {
    serde_json::from_value(value)
        .map_err(|error| format!("invalid learning outcome request: {error}"))
}

fn parse_fabrication_nats_request(payload: &[u8]) -> Result<FabricationNatsRequest, String> {
    let value = serde_json::from_slice::<Value>(payload)
        .map_err(|error| format!("invalid fabrication request json: {error}"))?;
    if let Ok(envelope) = serde_json::from_value::<FabricationNatsEnvelope>(value.clone()) {
        let FabricationNatsEnvelope {
            kind,
            message_type,
            operation,
            request,
            plan,
            analysis,
            instruction_analysis,
            outcome,
            fabrication_outcome,
            learning_outcome,
        } = envelope;
        if let Some(analysis) = analysis.or(instruction_analysis) {
            return Ok(FabricationNatsRequest::InstructionAnalysis(analysis));
        }
        if let Some(plan) = plan {
            return Ok(FabricationNatsRequest::Plan(plan));
        }
        if let Some(outcome) = outcome.or(fabrication_outcome) {
            return Ok(FabricationNatsRequest::FabricationOutcome(outcome));
        }
        if let Some(outcome) = learning_outcome {
            return Ok(FabricationNatsRequest::LearningOutcome(outcome));
        }
        let discriminator = kind
            .as_ref()
            .or(message_type.as_ref())
            .or(operation.as_ref())
            .map(|value| normalize_token(value));
        if let Some(token) = discriminator {
            let request_value = request.unwrap_or_else(|| value.clone());
            if discriminator_requests_learning_outcome(&token) {
                return parse_learning_outcome_nats_value(request_value)
                    .map(FabricationNatsRequest::LearningOutcome);
            }
            if discriminator_requests_fabrication_outcome(&token) {
                return parse_fabrication_outcome_nats_value(request_value)
                    .map(FabricationNatsRequest::FabricationOutcome);
            }
            if discriminator_requests_analysis(&token) {
                return parse_analysis_nats_value(request_value)
                    .map(FabricationNatsRequest::InstructionAnalysis);
            }
            if discriminator_requests_plan(&token) {
                return parse_plan_nats_value(request_value).map(FabricationNatsRequest::Plan);
            }
        }
    }
    if value.get("programs").is_some() {
        return parse_analysis_nats_value(value).map(FabricationNatsRequest::InstructionAnalysis);
    }
    if value.get("success").is_some() {
        return parse_learning_outcome_nats_value(value)
            .map(FabricationNatsRequest::LearningOutcome);
    }
    if value.get("outcome").is_some() {
        return parse_fabrication_outcome_nats_value(value)
            .map(FabricationNatsRequest::FabricationOutcome);
    }
    parse_plan_nats_value(value).map(FabricationNatsRequest::Plan)
}

async fn run_nats_loop(state: AppState) {
    let Some(nats) = state.nats.clone() else {
        println!("{SERVICE_NAME} nats loop disabled: NATS_URL is not configured");
        return;
    };
    println!(
        "{SERVICE_NAME} nats loop starting: subject={} queueGroup={} resultSubject={}",
        state.request_subject, state.queue_group, state.result_subject
    );
    let mut subscription = match nats
        .queue_subscribe(state.request_subject.clone(), state.queue_group.clone())
        .await
    {
        Ok(subscription) => subscription,
        Err(error) => {
            eprintln!("{SERVICE_NAME} nats subscribe failed: {error}");
            return;
        }
    };

    while let Some(message) = subscription.next().await {
        state
            .metrics
            .nats_messages_total
            .fetch_add(1, Ordering::Relaxed);
        let payload = message.payload.to_vec();
        if payload.len() > MAX_NATS_PAYLOAD_BYTES {
            state.metrics.errors_total.fetch_add(1, Ordering::Relaxed);
            eprintln!(
                "{SERVICE_NAME} rejected oversize nats request: bytes={} max={MAX_NATS_PAYLOAD_BYTES}",
                payload.len()
            );
            continue;
        }
        let task_state = state.clone();
        tokio::spawn(async move {
            match parse_fabrication_nats_request(&payload) {
                Ok(FabricationNatsRequest::Plan(request)) => {
                    let policy_snapshot = learning_policy_snapshot(&task_state).ok();
                    match plan_fabrication_with_policy(request, policy_snapshot.as_ref()) {
                        Ok(response) => {
                            task_state
                                .metrics
                                .plan_requests_total
                                .fetch_add(1, Ordering::Relaxed);
                            record_plan_metrics(&task_state, &response);
                            store_plan_response(&task_state, &response);
                            publish_plan_outputs(&task_state, &response).await;
                            publish_event(
                                &task_state,
                                "fabrication.plan.completed",
                                &response.request_id,
                                response.ok,
                            )
                            .await;
                        }
                        Err(error) => {
                            task_state
                                .metrics
                                .errors_total
                                .fetch_add(1, Ordering::Relaxed);
                            eprintln!("{SERVICE_NAME} failed nats fabrication plan: {error}");
                        }
                    }
                }
                Ok(FabricationNatsRequest::InstructionAnalysis(request)) => {
                    match analyze_instruction_request(request) {
                        Ok(response) => {
                            task_state
                                .metrics
                                .analysis_requests_total
                                .fetch_add(1, Ordering::Relaxed);
                            record_analysis_metrics(&task_state, &response);
                            store_analysis_response(&task_state, &response);
                            publish_analysis_outputs(&task_state, &response).await;
                            publish_event(
                                &task_state,
                                "fabrication.instructions.analyzed",
                                &response.request_id,
                                response.ok,
                            )
                            .await;
                        }
                        Err(error) => {
                            task_state
                                .metrics
                                .errors_total
                                .fetch_add(1, Ordering::Relaxed);
                            eprintln!("{SERVICE_NAME} failed nats instruction analysis: {error}");
                        }
                    }
                }
                Ok(FabricationNatsRequest::FabricationOutcome(request)) => {
                    task_state
                        .metrics
                        .learning_requests_total
                        .fetch_add(1, Ordering::Relaxed);
                    match learn_from_outcome(request) {
                        Ok((response, record)) => {
                            match store_learning_response(&task_state, &response, record) {
                                Ok(_) => {
                                    publish_learning_outputs(&task_state, &response).await;
                                    publish_event(
                                        &task_state,
                                        "fabrication.learning.observed",
                                        &response.request_id,
                                        response.ok,
                                    )
                                    .await;
                                }
                                Err(error) => {
                                    task_state
                                        .metrics
                                        .errors_total
                                        .fetch_add(1, Ordering::Relaxed);
                                    eprintln!("{SERVICE_NAME} failed nats learning store: {error}");
                                }
                            }
                        }
                        Err(error) => {
                            task_state
                                .metrics
                                .errors_total
                                .fetch_add(1, Ordering::Relaxed);
                            eprintln!("{SERVICE_NAME} failed nats fabrication outcome: {error}");
                        }
                    }
                }
                Ok(FabricationNatsRequest::LearningOutcome(request)) => {
                    task_state
                        .metrics
                        .learning_requests_total
                        .fetch_add(1, Ordering::Relaxed);
                    match learning_outcome_record(request) {
                        Ok(record) => {
                            let outcome_id = record.outcome_id.clone();
                            match store_learning_record(&task_state, record) {
                                Ok(snapshot) => {
                                    publish_learning_outcome_outputs(
                                        &task_state,
                                        &outcome_id,
                                        &snapshot,
                                    )
                                    .await;
                                    publish_event(
                                        &task_state,
                                        "fabrication.learning.outcome",
                                        &outcome_id,
                                        true,
                                    )
                                    .await;
                                }
                                Err(error) => {
                                    task_state
                                        .metrics
                                        .errors_total
                                        .fetch_add(1, Ordering::Relaxed);
                                    eprintln!(
                                        "{SERVICE_NAME} failed nats compact learning store: {error}"
                                    );
                                }
                            }
                        }
                        Err(error) => {
                            task_state
                                .metrics
                                .errors_total
                                .fetch_add(1, Ordering::Relaxed);
                            eprintln!(
                                "{SERVICE_NAME} failed nats compact learning outcome: {error}"
                            );
                        }
                    }
                }
                Err(error) => {
                    task_state
                        .metrics
                        .errors_total
                        .fetch_add(1, Ordering::Relaxed);
                    eprintln!("{SERVICE_NAME} invalid nats fabrication request: {error}");
                }
            }
        });
    }
}

