    #[test]
    fn additive_plan_flags_support_overhang_and_thin_wall_boundaries() {
        let response = plan_fabrication(FabricationPlanRequest {
            request_id: Some("unit-additive-manufacturability".to_string()),
            objective:
                "PLA prototype cover with unsupported overhang, long bridge, and thin-wall snap-fit tabs"
                    .to_string(),
            material: Some(material("pla", "polymer")),
            stock: None,
            tolerance_mm: Some(0.2),
            quantity: Some(1),
            machines: None,
            constraints: None,
            parts: None,
            design_inputs: None,
            existing_instructions: None,
            learning: None,
        })
        .expect("additive manufacturability plan should be generated");

        assert!(response
            .design
            .parts
            .iter()
            .any(|part| part.machine_kind == "fdm-printer"));
        assert_eq!(response.validation.severity, "warning");
        assert!(response
            .validation
            .findings
            .iter()
            .any(|finding| finding.code == "additive-support-orientation-boundary"));
        assert!(response
            .validation
            .findings
            .iter()
            .any(|finding| finding.code == "additive-thin-wall-boundary"));
        assert!(response
            .validation
            .failure_boundaries
            .iter()
            .any(|boundary| boundary.kind == "additive-support-boundary"
                && boundary.requires_human_intervention
                && boundary
                    .suggested_resolution
                    .contains("split unsupported features")));
        assert!(response
            .validation
            .failure_boundaries
            .iter()
            .any(|boundary| boundary.kind == "additive-thin-wall-boundary"
                && boundary
                    .suggested_resolution
                    .contains("minimum wall thickness")));
    }

    #[test]
    fn router_analysis_flags_profile_before_spindle_and_tab_stop_boundary() {
        let programs = vec![program(
            "unsafe-router",
            "cnc-router",
            &[
                "G21 G90 G54",
                "G1 X120 Y0 F900",
                "M0 inspect retained tabs and hold-down",
                "M30",
            ],
        )];

        let (analyzed, validation, improvements) = analyze_instruction_programs(&programs);

        assert_eq!(analyzed[0].machine_kind, "cnc-router");
        assert_eq!(validation.severity, "error");
        assert!(validation
            .findings
            .iter()
            .any(|finding| finding.code == "cut-before-spindle"));
        assert!(validation
            .findings
            .iter()
            .any(|finding| finding.code == "missing-spindle-start"));
        assert!(validation
            .failure_boundaries
            .iter()
            .any(|boundary| boundary.kind == "machine-safety-gate"));
        assert!(validation.failure_boundaries.iter().any(|boundary| {
            boundary.kind == "human-intervention" && boundary.requires_human_intervention
        }));
        assert!(!improvements
            .iter()
            .any(|improvement| improvement.action == "add-coordinate-reference"));

        let improved = improve_instruction_programs(&programs, &validation, &improvements);
        assert!(improved[0].changed);
        assert!(!improved[0].machine_ready);
        assert!(improved[0]
            .instructions
            .iter()
            .any(|line| line.contains("REVIEW: add verified spindle speed")));
        assert!(improved[0]
            .instructions
            .iter()
            .any(|line| line.contains("boundary machine-safety-gate")));
    }

