        assert!(improved[0].changed);
        assert!(!improved[0].machine_ready);
        assert!(improved[0]
            .instructions
            .iter()
            .any(|line| line.contains("boundary canned-cycle-boundary")));
        assert!(improved[0]
            .instructions
            .iter()
            .any(|line| line.contains("boundary tapping-cycle-boundary")));
