    #[test]
    fn fabrication_outcome_creates_reward_and_training_artifacts() {
        let (response, record) = learn_from_outcome(FabricationOutcomeRequest {
            request_id: Some("unit-outcome".to_string()),
            source_job_id: Some("plan-unit-artifact-plan-123".to_string()),
            source_artifact_id: Some("program-main".to_string()),
            part_id: Some("bracket".to_string()),
            program_id: Some("mill-bracket".to_string()),
            machine_id: Some("vertical-mill-1".to_string()),
            machine_kind: Some("vertical-mill".to_string()),
            operation_sequence: None,
            material: Some(material("aluminum", "metal")),
            outcome: "machine alarm; part scrapped after manual intervention".to_string(),
            completed: Some(false),
            machine_failure: Some(true),
            scrap: Some(true),
            human_intervention_required: Some(true),
            intervention_minutes: Some(18.0),
            duration_minutes: Some(42.0),
            dimensional_error_mm: Some(0.42),
            surface_quality: Some(0.25),
            observations: Some(vec!["spindle load spike".to_string()]),
            notes: Some(vec!["revise feeds and split the finish pass".to_string()]),
            reward_weights: None,
        })
        .expect("fabrication outcome should produce learning evidence");

        assert!(!response.ok);
        assert_eq!(response.state, "failed");
        assert_eq!(
            response.recommended_action,
            "reject-or-repostprocess-program"
        );
        assert!(response.reward < 0.0);
        assert!(response
            .observations
            .iter()
            .any(|observation| observation == "machine-failure"));
        assert_eq!(
            response.outcome_remediation.schema_version,
            "dd.fabrication.outcome-remediation.v1"
        );
        assert_eq!(
            response.outcome_remediation.status,
            "blocked-remediation-required"
        );
        assert!(response.outcome_remediation.human_review_required);
        assert!(response
            .outcome_remediation
            .root_causes
            .iter()
            .any(|cause| cause.category == "machine-failure-boundary"
                && cause.affected_program_id.as_deref() == Some("mill-bracket")));
        assert!(response
            .outcome_remediation
            .actions
            .iter()
            .any(|action| action.phase == "machine-release"
                && action.target_state == "failed-until-resolved"));
        assert!(response
            .outcome_remediation
            .learning_signals
            .iter()
            .any(|signal| signal.starts_with("outcome-root-cause:")));
        assert_eq!(
            response
                .mdp_update
                .get("schemaVersion")
                .and_then(Value::as_str),
            Some("dd.fabrication.learning-experience.v1")
        );
        assert!(response
            .mdp_update
            .get("outcomeRemediation")
            .and_then(|plan| plan.get("actions"))
            .and_then(Value::as_array)
            .is_some_and(|actions| !actions.is_empty()));
        assert_eq!(
            response
                .neural_example
                .get("schemaVersion")
                .and_then(Value::as_str),
            Some("dd.fabrication.neural-example.v1")
        );
        assert!(response
            .neural_example
            .get("features")
            .and_then(|features| features.get("outcomeRemediationSignals"))
            .and_then(Value::as_array)
            .is_some_and(|signals| !signals.is_empty()));

        let job = stored_learning_job(&response);
        assert_eq!(job.record.kind, "fabrication-learning-outcome");
        assert!(job.artifacts.contains_key("outcome-learning-event"));
        assert!(job.artifacts.contains_key("reward-signal"));
        assert!(job.artifacts.contains_key("mdp-experience"));
        assert!(job.artifacts.contains_key("outcome-remediation-plan"));
        assert!(job.artifacts.contains_key("pomdp-observations"));
        assert!(job.artifacts.contains_key("neural-example"));
        let remediation = job
            .artifacts
            .get("outcome-remediation-plan")
            .expect("outcome remediation artifact should be retained");
        assert_eq!(
            remediation
                .content
                .get("schemaVersion")
                .and_then(Value::as_str),
            Some("dd.fabrication.outcome-remediation.v1")
        );
        assert!(remediation
            .content
            .get("rootCauses")
            .and_then(Value::as_array)
            .is_some_and(|causes| !causes.is_empty()));

        let mut memory = LearningMemory::new(8);
        memory.insert(record);
        let snapshot = memory.snapshot();
        assert_eq!(snapshot.outcome_count, 1);
        assert_eq!(snapshot.failures, 1);
        assert!(snapshot.average_reward < 0.0);
        assert!(snapshot
            .method_preferences
            .iter()
            .any(|preference| preference.key == "milling"));
    }

    #[test]
    fn learning_outcomes_memory_endpoint_exposes_bounded_records_and_policy_snapshot() {
        let first_success = learning_outcome_record(LearningOutcomeRequest {
            request_id: Some("memory-success-1".to_string()),
            job_id: Some("plan-memory-1".to_string()),
            objective: Some("printed jig with milled datum".to_string()),
            material: Some(material("petg", "polymer")),
            manufacturing_methods: Some(vec!["additive-print".to_string(), "milling".to_string()]),
            machine_kind: Some("vertical-mill".to_string()),
            operation_sequence: Some(vec!["additive-print".to_string(), "milling".to_string()]),
            assembly_strategy: Some("printed body plus milled datum face".to_string()),
            success: true,
            reward: Some(2.5),
            observations: Some(vec!["datum inspection passed".to_string()]),
            notes: Some(vec!["keep hybrid route".to_string()]),
        })
        .expect("first memory outcome should be valid");
        let second_success = learning_outcome_record(LearningOutcomeRequest {
            request_id: Some("memory-success-2".to_string()),
            job_id: Some("plan-memory-2".to_string()),
            objective: Some("printed bracket with milled bearing pad".to_string()),
            material: Some(material("petg", "polymer")),
            manufacturing_methods: Some(vec!["additive-print".to_string(), "milling".to_string()]),
            machine_kind: Some("vertical-mill".to_string()),
            operation_sequence: Some(vec!["additive-print".to_string(), "milling".to_string()]),
            assembly_strategy: Some("printed body plus milled datum face".to_string()),
            success: true,
            reward: Some(3.0),
            observations: Some(vec!["bearing pad passed".to_string()]),
            notes: Some(vec!["reuse datum allowance".to_string()]),
        })
        .expect("second memory outcome should be valid");
        let failed_route = learning_outcome_record(LearningOutcomeRequest {
            request_id: Some("memory-failure-1".to_string()),
            job_id: Some("plan-memory-3".to_string()),
            objective: Some("single-piece milled PETG jig".to_string()),
            material: Some(material("petg", "polymer")),
            manufacturing_methods: Some(vec!["milling".to_string()]),
            machine_kind: Some("vertical-mill".to_string()),
            operation_sequence: Some(vec!["milling".to_string()]),
            assembly_strategy: Some("single-piece machining".to_string()),
            success: false,
            reward: Some(-2.0),
            observations: Some(vec!["thin wall chatter".to_string()]),
            notes: Some(vec!["prefer printed blank before milling".to_string()]),
        })
        .expect("failed memory outcome should be valid");

        let mut memory = LearningMemory::new(2);
        memory.insert(first_success);
        memory.insert(second_success);
        memory.insert(failed_route);
        let payload = learning_outcomes_memory_response(&memory);

        assert_eq!(
            payload.get("schemaVersion").and_then(Value::as_str),
            Some("dd.fabrication.learning-outcome-memory.v1")
        );
        assert_eq!(payload.get("outcomeCount").and_then(Value::as_u64), Some(2));
        assert_eq!(payload.get("maxOutcomes").and_then(Value::as_u64), Some(2));
        assert!(payload
            .get("routes")
            .and_then(Value::as_array)
            .is_some_and(|routes| routes
                .iter()
                .any(|route| route.as_str() == Some("GET /fabrication/learning/outcomes"))));
        let outcomes = payload
            .get("outcomes")
            .and_then(Value::as_array)
            .expect("bounded outcomes should be present");
        assert!(!outcomes
            .iter()
            .any(|outcome| outcome.get("requestId").and_then(Value::as_str)
                == Some("memory-success-1")));
        assert!(outcomes
            .iter()
            .any(|outcome| outcome.get("requestId").and_then(Value::as_str)
                == Some("memory-success-2")));
        assert!(outcomes
            .iter()
            .any(|outcome| outcome.get("requestId").and_then(Value::as_str)
                == Some("memory-failure-1")));
        assert_eq!(
            payload
                .get("policy")
                .and_then(|policy| policy.get("outcomeCount"))
                .and_then(Value::as_u64),
            Some(2)
        );
        assert!(payload
            .get("policy")
            .and_then(|policy| policy.get("methodCombinationPreferences"))
            .and_then(Value::as_array)
            .is_some_and(|preferences| preferences
                .iter()
                .any(|preference| preference.get("key").and_then(Value::as_str)
                    == Some("additive-print+milling"))));
        assert!(payload
            .get("policy")
            .and_then(|policy| policy.get("remediationRisks"))
            .and_then(Value::as_array)
            .is_some_and(|risks| risks
                .iter()
                .any(|risk| risk.get("method").and_then(Value::as_str) == Some("milling"))));
    }

    #[test]
    fn compact_learning_outcomes_prefer_successful_hybrid_strategy() {
        let first_success = learning_outcome_record(LearningOutcomeRequest {
            request_id: Some("hybrid-success-1".to_string()),
            job_id: Some("plan-hybrid-1".to_string()),
            objective: Some("printed housing with turned bearing insert".to_string()),
            material: Some(material("petg", "polymer")),
            manufacturing_methods: Some(vec!["additive-print".to_string(), "turning".to_string()]),
            machine_kind: None,
            operation_sequence: None,
            assembly_strategy: Some("printed body plus turned insert".to_string()),
            success: true,
            reward: Some(3.2),
            observations: Some(vec!["press-fit passed".to_string()]),
            notes: Some(vec!["reuse insert allowance".to_string()]),
        })
        .expect("first compact learning outcome should be valid");
        let second_success = learning_outcome_record(LearningOutcomeRequest {
            request_id: Some("hybrid-success-2".to_string()),
            job_id: Some("plan-hybrid-2".to_string()),
            objective: Some("printed knob with turned brass threaded core".to_string()),
            material: Some(material("petg", "polymer")),
            manufacturing_methods: Some(vec!["additive-print".to_string(), "turning".to_string()]),
            machine_kind: None,
            operation_sequence: None,
            assembly_strategy: Some("printed body plus turned insert".to_string()),
            success: true,
            reward: Some(2.4),
            observations: Some(vec!["thread gauge passed".to_string()]),
            notes: Some(vec!["recorded for reuse".to_string()]),
        })
        .expect("second compact learning outcome should be valid");
        let failed_milling = learning_outcome_record(LearningOutcomeRequest {
            request_id: Some("hybrid-failure-1".to_string()),
            job_id: Some("plan-hybrid-3".to_string()),
            objective: Some("single-piece milled plastic housing".to_string()),
            material: Some(material("petg", "polymer")),
            manufacturing_methods: Some(vec!["milling".to_string()]),
            machine_kind: None,
            operation_sequence: None,
            assembly_strategy: Some("single-piece machining".to_string()),
            success: false,
            reward: Some(-1.0),
            observations: Some(vec!["thin wall chatter".to_string()]),
            notes: Some(vec!["split into printed body and turned insert".to_string()]),
        })
        .expect("failed compact learning outcome should still be valid evidence");

        let mut memory = LearningMemory::new(8);
        memory.insert(first_success);
        memory.insert(second_success);
        memory.insert(failed_milling);
        let snapshot = memory.snapshot();

        assert_eq!(snapshot.outcome_count, 3);
        assert_eq!(snapshot.successes, 2);
        assert_eq!(snapshot.failures, 1);
        assert!(snapshot.method_preferences.iter().any(|preference| {
            preference.key == "additive-print"
                && preference.samples == 2
                && preference.recommendation == "prefer"
        }));
        assert!(snapshot.method_preferences.iter().any(|preference| {
            preference.key == "turning"
                && preference.samples == 2
                && preference.recommendation == "prefer"
        }));
        assert!(snapshot
            .method_combination_preferences
            .iter()
            .any(|preference| {
                preference.key == "additive-print+turning"
                    && preference.samples == 2
                    && preference.recommendation == "prefer"
            }));
        assert!(snapshot.assembly_preferences.iter().any(|preference| {
            preference.key == "printed body plus turned insert"
                && preference.samples == 2
                && preference.recommendation == "prefer"
        }));
        assert!(snapshot.remediation_risks.iter().any(|risk| {
            risk.key == "milling@petg"
                && risk.method == "milling"
                && risk.failures == 1
                && risk.material.as_deref() == Some("petg")
                && risk
                    .observations
                    .iter()
                    .any(|observation| observation.contains("chatter"))
                && risk
                    .recommended_actions
                    .iter()
                    .any(|action| action.contains("split-into-printed-body-and-turned-insert"))
        }));
        assert!(snapshot
            .neural_training_examples
            .iter()
            .any(|example| example.contains("methods=additive-print+turning")));
    }

    #[test]
    fn learned_remediation_risks_feed_future_plan_policy() {
        let (_response, record) = learn_from_outcome(FabricationOutcomeRequest {
            request_id: Some("failed-petg-mill".to_string()),
            source_job_id: Some("plan-petg-mill".to_string()),
            source_artifact_id: Some("program-petg-pocket".to_string()),
            part_id: Some("petg-pocket".to_string()),
            program_id: Some("program-petg-pocket".to_string()),
            machine_id: Some("vmill-1".to_string()),
            machine_kind: Some("vertical-mill".to_string()),
            operation_sequence: None,
            material: Some(material("petg", "polymer")),
            outcome: "tool chatter alarm scrapped thin-wall pocket".to_string(),
            completed: Some(false),
            machine_failure: Some(true),
            scrap: Some(true),
            human_intervention_required: Some(true),
            intervention_minutes: Some(18.0),
            duration_minutes: Some(42.0),
            dimensional_error_mm: Some(0.7),
            surface_quality: Some(0.25),
            observations: Some(vec![
                "spindle alarm".to_string(),
                "thin wall chatter".to_string(),
                "boundary-kind:machine-envelope".to_string(),
                "boundary-severity:error".to_string(),
                "boundary-program:program-petg-pocket".to_string(),
                "boundary-line:24".to_string(),
                "resolution-action:split-job-or-part".to_string(),
            ]),
            notes: Some(vec![
                "split thin wall into printed shell and mill datum insert".to_string(),
            ]),
            reward_weights: None,
        })
        .expect("failed outcome should become learning evidence");
        let mut memory = LearningMemory::new(8);
        memory.insert(record);
        let snapshot = memory.snapshot();
        let risk = snapshot
            .remediation_risks
            .iter()
            .find(|risk| risk.key == "milling@petg")
            .expect("failed milling should produce a material-specific remediation risk");
        assert_eq!(risk.severity, "high");
        assert_eq!(risk.review_action, "avoid-learned-risk-milling-petg");
        assert!(risk
            .observations
            .iter()
            .any(|observation| observation.contains("machine-failure")));
        assert!(snapshot.boundary_learning_examples.iter().any(|example| {
            example.contains("boundary-memory")
                && example.contains("boundary-kind:machine-envelope")
                && example.contains("resolution-action:split-job-or-part")
        }));

        let learned = plan_fabrication_with_policy(
            FabricationPlanRequest {
                request_id: Some("future-petg-mill".to_string()),
                objective: "PETG thin-wall pocket with datum face".to_string(),
                material: Some(material("petg", "polymer")),
                stock: None,
                tolerance_mm: Some(0.08),
                quantity: Some(1),
                machines: Some(vec![MachineProfile {
                    id: "vmill-1".to_string(),
                    kind: "vertical-mill".to_string(),
                    controller: Some("haas-gcode".to_string()),
                    materials: Some(vec!["petg".to_string()]),
                    work_envelope_mm: Some(vec![300.0, 180.0, 120.0]),
                    axes: Some(3),
                    operations: Some(vec!["face".to_string(), "contour".to_string()]),
                    profile_evidence: None,
                }]),
                constraints: None,
                parts: Some(vec![RequestedPart {
                    id: "petg-pocket".to_string(),
                    description: "thin-wall PETG pocket with machined datum face".to_string(),
                    material: Some(material("petg", "polymer")),
                    preferred_method: Some("milling".to_string()),
                    tolerance_mm: Some(0.08),
                }]),
                design_inputs: None,
                existing_instructions: None,
                learning: None,
            },
            Some(&snapshot),
        )
        .expect("future plan should include learned risk feedback");

        assert!(learned
            .learning
            .pomdp_observations
            .iter()
            .any(|observation| observation.starts_with("learned-remediation-risk:milling@petg:")));
        assert!(learned
            .learning
            .actions
            .iter()
            .any(|action| action == "avoid-learned-risk-milling-petg"));
        assert!(learned
            .learning
            .training_examples
            .iter()
            .any(|example| example.contains("remediation-risk key=milling@petg")));
        assert!(learned
            .learning
            .training_examples
            .iter()
            .any(|example| example.contains("boundary-memory")
                && example.contains("boundary-kind:machine-envelope")));
        assert!(learned
            .learning
            .pomdp_observations
            .iter()
            .any(|observation| observation.starts_with("learned-boundary-memory:")));
        assert!(learned
            .learning
            .neural_training_corpus
            .examples
            .iter()
            .any(|example| example.source == "policy-memory"
                && example
                    .labels
                    .iter()
                    .any(|label| label == "learned-boundary-memory")
                && example
                    .observations
                    .iter()
                    .any(|observation| observation.contains("boundary-memory"))));
        assert!(learned
            .learning
            .pomdp_belief_state
            .hidden_states
            .iter()
            .any(|state| state.state == "machine-failure-risk"
                && state
                    .evidence
                    .iter()
                    .any(|evidence| evidence.contains("learned-remediation-risk:milling@petg"))));
        assert_eq!(
            learned.learning.release_probe_plan.release_state,
            "blocked-pending-release-probes"
        );
        assert!(learned
            .learning
            .release_probe_plan
            .probes
            .iter()
            .any(|probe| probe.target_state == "machine-failure-risk"
                && probe.priority == "required"
                && probe.release_blocker));
        assert!(learned
            .learning
            .release_probe_plan
            .required_before_release
            .iter()
            .any(|requirement| {
                requirement
                    == "learned-remediation-risk:review-prior-failure-outcome-before-release"
            }));
        assert!(learned
            .learning
            .release_probe_plan
            .notes
            .iter()
            .any(|note| note.contains("Learned remediation memory contributed")));
        assert!(learned
            .machine_release
            .blockers
            .iter()
            .any(|blocker| blocker.source == "release-probe"
                && blocker.blocker_type == "machine-failure-risk"
                && blocker
                    .reason
                    .contains("learned-remediation-risk:milling@petg")));
        assert!(learned
            .machine_release
            .checklist
            .iter()
            .any(|item| item.item == "release-probes"
                && item.status == "blocked"
                && item.evidence.contains("blocked-pending-release-probes")));
        let mdp_request = fabrication_mdp_request(&learned);
        assert!(mdp_request
            .get("transitions")
            .and_then(Value::as_array)
            .is_some_and(|transitions| transitions.iter().any(|transition| {
                transition.get("action").and_then(Value::as_str)
                    == Some("avoid-learned-risk-milling-petg")
                    && transition.get("nextState").and_then(Value::as_str)
                        == Some("failed-until-resolved")
            })));
    }

